```typescript
export async function runMap(): Promise<void> {
  const args = process.argv.slice(2); // ["map", "<dir>", "<type:id>"]
  const dirArg = args[1];
  const entityArg = args[2];

  if (!dirArg || !entityArg) {
    console.error("Usage: brain map <directory> <type:id>");
    console.error("Example: brain map ./services/auth project:abc123");
    process.exit(1);
  }

  // 1. Resolve and validate directory
  const dir = resolve(dirArg);
  if (!existsSync(dir) || !statSync(dir).isDirectory()) {
    console.error(`Not a directory: ${dir}`);
    process.exit(1);
  }

  // 2. Parse entity reference
  const colonIdx = entityArg.indexOf(":");
  if (colonIdx === -1) {
    console.error("Entity must be in type:id format (e.g. project:abc123)");
    process.exit(1);
  }
  const entityType = entityArg.slice(0, colonIdx) as SupportedType;
  const entityRawId = entityArg.slice(colonIdx + 1);
  if (!SUPPORTED_TYPES.includes(entityType)) {
    console.error(`Unsupported entity type: ${entityType}. Supported: ${SUPPORTED_TYPES.join(", ")}`);
    process.exit(1);
  }
  if (!entityRawId) {
    console.error("Entity ID is empty");
    process.exit(1);
  }

  // 3. Load config and validate entity
  const config = await requireConfig();
  const client = new BrainHttpClient(config);

  let detail: EntityDetailResult;
  try {
    detail = (await client.getEntityDetail(entityArg)) as EntityDetailResult;
  } catch (error) {
    console.error(`Entity not found or not in workspace: ${entityArg}`);
    console.error(error instanceof Error ? error.message : String(error));
    process.exit(1);
  }

  // 4. Resolve ancestry (parent project for feature/task)
  const ancestry = await resolveAncestry(client, detail, entityType);

  // 5. Generate CLAUDE.md content
  const content = generateMapContent(entityType, detail.entity, ancestry);

  // 6. Write to CLAUDE.md
  await writeMapBlock(dir, content);

  // 7. Print summary
  const entityLabel = `${entityType}: "${detail.entity.name}"`;
  const projectLabel = ancestry.project ? ` (project: "${ancestry.project.name}")` : "";
  console.log(`Mapped ${dir}/CLAUDE.md -> ${entityLabel}${projectLabel}`);
}
```

