  const ancestry = await resolveAncestry(client, detail, entityType);

  // 5. Generate CLAUDE.md content
  const content = generateMapContent(entityType, detail.entity, ancestry);

  // 6. Write to CLAUDE.md
  await writeMapBlock(dir, content);

  // 7. Print summary
  const entityLabel = `${entityType}: "${detail.entity.name}"`;
  const projectLabel = ancestry.project ? ` (project: "${ancestry.project.name}")` : "";
  console.log(`Mapped ${dir}/CLAUDE.md -> ${entityLabel}${projectLabel}`);
}
```

**`runUnmap()` implementation outline:**

```typescript
export async function runUnmap(): Promise<void> {
  const args = process.argv.slice(2); // ["unmap", "<dir>"]
  const dirArg = args[1];

  if (!dirArg) {
    console.error("Usage: brain unmap <directory>");
    process.exit(1);
  }

  const dir = resolve(dirArg);
  const claudeMdPath = join(dir, "CLAUDE.md");

  if (!existsSync(claudeMdPath)) {
    console.error(`No CLAUDE.md found in ${dir}`);
    process.exit(1);
  }

  const file = Bun.file(claudeMdPath);
  let content = await file.text();

  const startIdx = content.indexOf(MAP_MARKER_START);
  const endIdx = content.indexOf(MAP_MARKER_END);

  if (startIdx === -1 || endIdx === -1) {
    console.error(`No brain mapping found in ${claudeMdPath}`);
    process.exit(1);
  }

  // Remove marker block (including trailing newline)
  const beforeBlock = content.slice(0, startIdx);
  const afterBlock = content.slice(endIdx + MAP_MARKER_END.length);
  content = (beforeBlock + afterBlock).replace(/\n{3,}/g, "\n\n").trim();

  if (content.length === 0) {
    unlinkSync(claudeMdPath);
    console.log(`Removed ${claudeMdPath} (was empty after unmap)`);
  } else {
    await Bun.write(claudeMdPath, content + "\n");
    console.log(`Removed brain mapping from ${claudeMdPath}`);
  }
}
```

**`resolveAncestry()` helper:**

```typescript
type Ancestry = {
  project?: { id: string; name: string };
  feature?: { id: string; name: string };
};

async function resolveAncestry(
  client: BrainHttpClient,
  detail: EntityDetailResult,
  entityType: SupportedType,
): Promise<Ancestry> {
  if (entityType === "project") {
    return { project: { id: detail.entity.id, name: detail.entity.name } };
  }

  if (entityType === "feature") {
    const parentProject = detail.relationships.find(
      (r) => r.kind === "project" && r.relationKind === "has_feature" && r.direction === "incoming",
    );
    return {
      project: parentProject ? { id: parentProject.id, name: parentProject.name } : undefined,
      feature: { id: detail.entity.id, name: detail.entity.name },
    };
  }

  // entityType === "task"
  // Try direct project relationship first
  const directProject = detail.relationships.find(
    (r) => r.kind === "project" && r.direction === "outgoing" && r.relationKind === "belongs_to",
  );

  const parentFeature = detail.relationships.find(
    (r) => r.kind === "feature" && r.relationKind === "has_task" && r.direction === "incoming",
  );

  let project: Ancestry["project"];

  if (directProject) {
    project = { id: directProject.id, name: directProject.name };
  } else if (parentFeature) {
    // Resolve feature's parent project via a second HTTP call
    try {
      const featureDetail = (await client.getEntityDetail(
        `feature:${parentFeature.id}`,
      )) as EntityDetailResult;
      const featureParentProject = featureDetail.relationships.find(
        (r) => r.kind === "project" && r.relationKind === "has_feature" && r.direction === "incoming",
      );
      if (featureParentProject) {
        project = { id: featureParentProject.id, name: featureParentProject.name };
      }
    } catch {
      // Could not resolve feature's project -- proceed without it
    }
  }

  return {
    project,
    feature: parentFeature ? { id: parentFeature.id, name: parentFeature.name } : undefined,
  };
}
```

**`generateMapContent()` helper:**

```typescript
function generateMapContent(
  entityType: SupportedType,
  entity: EntityDetailResult["entity"],
  ancestry: Ancestry,
): string {
  switch (entityType) {
    case "project":
      return projectTemplate(entity);
    case "feature":
      return featureTemplate(entity, ancestry);
    case "task":
      return taskTemplate(entity, ancestry);
  }
}
