function taskTemplate(entity: EntityDetailResult["entity"], ancestry: Ancestry): string {
  const lines: string[] = [];
  const projectSuffix = ancestry.project ? ` (project: "${ancestry.project.name}")` : "";
  lines.push(`# Brain: Task -- "${entity.name}"${projectSuffix}`);
  lines.push("");
  lines.push(`This directory is mapped to brain graph entity \`task:${entity.id}\`.`);

  if (ancestry.project) {
    lines.push(`Parent project: \`project:${ancestry.project.id}\` ("${ancestry.project.name}").`);
  }
  if (ancestry.feature) {
    lines.push(`Parent feature: \`feature:${ancestry.feature.id}\` ("${ancestry.feature.name}").`);
  }

  lines.push("");
  lines.push("When using Brain MCP tools from files in this directory:");
  lines.push(`- Pass \`task_id: "${entity.id}"\` to task-scoped tools (\`get_task_context\`, \`update_task_status\`, \`get_task_dependencies\`, \`create_subtask\`).`);

  if (ancestry.project) {
    lines.push(`- Pass \`project_id: "${ancestry.project.id}"\` to project-scoped tools.`);
  }

  lines.push(`- Call \`get_task_context\` with \`task_id: "${entity.id}"\` at session start for full task subgraph.`);
  return lines.join("\n");
}
