 1тЖТ#!/usr/bin/env bun
 2тЖТ
 3тЖТimport { runInit } from "./commands/init";
 4тЖТimport { runLoadContext, runCheckUpdates, runEndSession } from "./commands/system";
 5тЖТimport { runCheckCommit, runLogCommit } from "./commands/git-hooks";
 6тЖТ
 7тЖТconst args = process.argv.slice(2);
 8тЖТconst command = args[0];
 9тЖТconst subcommand = args[1];
10тЖТ
11тЖТasync function main(): Promise<void> {
12тЖТ  switch (command) {
13тЖТ    case "init":
14тЖТ      await runInit();
15тЖТ      break;
16тЖТ
17тЖТ    case "system":
18тЖТ      switch (subcommand) {
19тЖТ        case "load-context":
20тЖТ          await runLoadContext();
21тЖТ          break;
22тЖТ        case "check-updates":
23тЖТ          await runCheckUpdates();
24тЖТ          break;
25тЖТ        case "end-session":
26тЖТ          await runEndSession();
27тЖТ          break;
28тЖТ        default:
29тЖТ          console.error(`Unknown system subcommand: ${subcommand}`);
30тЖТ          console.error("Available: load-context, check-updates, end-session");
31тЖТ          process.exit(1);
32тЖТ      }
33тЖТ      break;
34тЖТ
35тЖТ    case "check-commit":
36тЖТ      await runCheckCommit();
37тЖТ      break;
38тЖТ
39тЖТ    case "log-commit":
40тЖТ      await runLogCommit();
41тЖТ      break;
42тЖТ
43тЖТ    case "mcp":
44тЖТ      // MCP stdio server тАФ import dynamically to avoid loading deps unless needed
45тЖТ      const { runMcpServer } = await import("./mcp-server");
46тЖТ      await runMcpServer();
47тЖТ      break;
48тЖТ
49тЖТ    case "help":
50тЖТ    case "--help":
51тЖТ    case "-h":
52тЖТ      printHelp();
53тЖТ      break;
54тЖТ
55тЖТ    default:
56тЖТ      if (command) {
57тЖТ        console.error(`Unknown command: ${command}`);
58тЖТ      }
59тЖТ      printHelp();
60тЖТ      process.exit(command ? 1 : 0);
61тЖТ  }
62тЖТ}
63тЖТ
64тЖТfunction printHelp(): void {
65тЖТ  console.log(`
66тЖТbrain тАФ Connect coding agents to the Brain knowledge graph
67тЖТ
68тЖТUsage:
69тЖТ  brain init                     Set up Brain integration (auth, MCP, hooks, commands, git hooks)
70тЖТ  brain system load-context      Load workspace info (SessionStart hook)
71тЖТ  brain system check-updates     Check for graph updates (UserPromptSubmit hook)
72тЖТ  brain system end-session       End agent session (SessionEnd hook)
73тЖТ  brain check-commit             Pre-commit hook: check for task completion
74тЖТ  brain log-commit               Deprecated no-op (GitHub webhook ingests commits)
75тЖТ  brain mcp                      Start MCP stdio server
76тЖТ
77тЖТEnvironment:
78тЖТ  BRAIN_SERVER_URL      Brain server URL (default: http://localhost:3000)
79тЖТ  BRAIN_WORKSPACE_ID    Workspace ID (required for init)
80тЖТ
81тЖТConfig:
82тЖТ  ~/.brain/config.json  Per-repo workspace credentials
83тЖТ`);
84тЖТ}
85тЖТ
86тЖТmain().catch((error) => {
87тЖТ  console.error(error instanceof Error ? error.message : error);
88тЖТ  process.exit(1);
89тЖТ});
