  1тЖТimport { existsSync, mkdirSync, statSync } from "node:fs";
  2тЖТimport { join, dirname, resolve } from "node:path";
  3тЖТimport { homedir } from "node:os";
  4тЖТ
  5тЖТconst BRAIN_DIR = join(homedir(), ".brain");
  6тЖТconst CONFIG_PATH = join(BRAIN_DIR, "config.json");
  7тЖТ
  8тЖТ/** Resolved config for a single repo тАФ shape consumed by BrainHttpClient and all commands. */
  9тЖТexport type BrainConfig = {
 10тЖТ  server_url: string;
 11тЖТ  workspace: string;
 12тЖТ  api_key: string;
 13тЖТ};
 14тЖТ
 15тЖТ/** Per-repo auth entry in ~/.brain/config.json */
 16тЖТexport type RepoConfig = {
 17тЖТ  workspace: string;
 18тЖТ  api_key: string;
 19тЖТ};
 20тЖТ
 21тЖТ/** Root shape of ~/.brain/config.json */
 22тЖТexport type BrainGlobalConfig = {
 23тЖТ  server_url: string;
 24тЖТ  repos: Record<string, RepoConfig>;
 25тЖТ};
 26тЖТ
 27тЖТ// ---------------------------------------------------------------------------
 28тЖТ// Git root
 29тЖТ// ---------------------------------------------------------------------------
 30тЖТ
 31тЖТ/**
 32тЖТ * Find the main repository root from any path, including worktrees.
 33тЖТ *
 34тЖТ * In a regular repo, `.git` is a directory тЖТ that dir is the root.
 35тЖТ * In a worktree, `.git` is a file containing `gitdir: /path/to/main/.git/worktrees/<name>`.
 36тЖТ * We follow the pointer back to the main repo so all worktrees share one config key.
 37тЖТ */
 38тЖТexport function findGitRoot(from: string): string | undefined {
 39тЖТ  let dir = from;
 40тЖТ  while (dir !== "/") {
 41тЖТ    const gitPath = join(dir, ".git");
 42тЖТ    if (existsSync(gitPath)) {
 43тЖТ      if (statSync(gitPath).isFile()) {
 44тЖТ        return resolveWorktreeMainRoot(gitPath) ?? dir;
 45тЖТ      }
 46тЖТ      return dir;
 47тЖТ    }
 48тЖТ    dir = dirname(dir);
 49тЖТ  }
 50тЖТ  return undefined;
 51тЖТ}
 52тЖТ
 53тЖТ/** Read a worktree .git file and resolve to the main repo root. */
 54тЖТfunction resolveWorktreeMainRoot(gitFile: string): string | undefined {
 55тЖТ  try {
 56тЖТ    const content = Bun.file(gitFile).textSync().trim();
 57тЖТ    const match = content.match(/^gitdir:\s*(.+)$/);
 58тЖТ    if (!match) return undefined;
 59тЖТ
 60тЖТ    const gitdir = resolve(dirname(gitFile), match[1]);
 61тЖТ    const dotGit = gitdir.replace(/\/worktrees\/[^/]+$/, "");
 62тЖТ    return dirname(dotGit);
 63тЖТ  } catch {
 64тЖТ    return undefined;
 65тЖТ  }
 66тЖТ}
 67тЖТ
 68тЖТ// ---------------------------------------------------------------------------
 69тЖТ// Global config (~/.brain/config.json)
 70тЖТ// ---------------------------------------------------------------------------
 71тЖТ
 72тЖТfunction ensureBrainDir(): void {
 73тЖТ  if (!existsSync(BRAIN_DIR)) mkdirSync(BRAIN_DIR, { recursive: true });
 74тЖТ}
 75тЖТ
 76тЖТexport async function loadGlobalConfig(): Promise<BrainGlobalConfig | undefined> {
 77тЖТ  const file = Bun.file(CONFIG_PATH);
 78тЖТ  if (!(await file.exists())) return undefined;
 79тЖТ  try {
 80тЖТ    return await file.json() as BrainGlobalConfig;
 81тЖТ  } catch {
 82тЖТ    return undefined;
 83тЖТ  }
 84тЖТ}
 85тЖТ
 86тЖТexport async function saveGlobalConfig(config: BrainGlobalConfig): Promise<void> {
 87тЖТ  ensureBrainDir();
 88тЖТ  await Bun.write(CONFIG_PATH, JSON.stringify(config, null, 2) + "\n");
 89тЖТ}
 90тЖТ
 91тЖТ/** Upsert a repo entry in the global config. Creates the file if needed. */
 92тЖТexport async function saveRepoConfig(serverUrl: string, gitRoot: string, repo: RepoConfig): Promise<void> {
 93тЖТ  const global = (await loadGlobalConfig()) ?? { server_url: serverUrl, repos: {} };
 94тЖТ  global.server_url = serverUrl;
 95тЖТ  global.repos[gitRoot] = repo;
 96тЖТ  await saveGlobalConfig(global);
 97тЖТ}
 98тЖТ
 99тЖТ// ---------------------------------------------------------------------------
100тЖТ// Resolved config (what consumers use)
101тЖТ// ---------------------------------------------------------------------------
102тЖТ
103тЖТ/** Resolve BrainConfig for the current repo from ~/.brain/config.json.
104тЖТ *  The server URL can be overridden via the BRAIN_SERVER_URL env var. */
105тЖТexport async function loadConfig(): Promise<BrainConfig | undefined> {
106тЖТ  const gitRoot = findGitRoot(process.cwd());
107тЖТ  const global = await loadGlobalConfig();
108тЖТ  if (global && gitRoot && global.repos[gitRoot]) {
109тЖТ    const repo = global.repos[gitRoot];
110тЖТ    const serverUrl = process.env.BRAIN_SERVER_URL ?? global.server_url;
111тЖТ    return { server_url: serverUrl, workspace: repo.workspace, api_key: repo.api_key };
112тЖТ  }
113тЖТ  return undefined;
114тЖТ}
115тЖТ
116тЖТexport async function requireConfig(): Promise<BrainConfig> {
117тЖТ  const config = await loadConfig();
118тЖТ  if (!config) {
119тЖТ    console.error("Brain not configured. Run: brain init");
120тЖТ    process.exit(1);
121тЖТ  }
122тЖТ  return config;
123тЖТ}
124тЖТ
125тЖТ

