 63тЖТ/** List active decisions, optionally scoped to a project and/or area */
 64тЖТexport async function listProjectDecisions(input: {
 65тЖТ  surreal: Surreal;
 66тЖТ  workspaceRecord: RecordId<"workspace", string>;
 67тЖТ  projectRecord?: RecordId<"project", string>;
 68тЖТ  area?: string;
 69тЖТ}): Promise<{
 70тЖТ  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 71тЖТ  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 72тЖТ  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 73тЖТ}> {
 74тЖТ  const projectFilter = input.projectRecord
 75тЖТ    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
 76тЖТ    : "";
 77тЖТ  const areaFilter = input.area
 78тЖТ    ? `AND category = $area`
 79тЖТ    : "";
 80тЖТ
 81тЖТ  const [rows] = await input.surreal
 82тЖТ    .query<[DecisionRow[]]>(
 83тЖТ      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 84тЖТ       FROM decision
 85тЖТ       WHERE workspace = $workspace
 86тЖТ         ${projectFilter}
 87тЖТ         ${areaFilter}
 88тЖТ       ORDER BY created_at DESC LIMIT 50;`,
 89тЖТ      {
 90тЖТ        workspace: input.workspaceRecord,
 91тЖТ        ...(input.projectRecord ? { project: input.projectRecord } : {}),
 92тЖТ        ...(input.area ? { area: input.area } : {}),
 93тЖТ      },
 94тЖТ    )
 95тЖТ    .collect<[DecisionRow[]]>();
 96тЖТ
 97тЖТ  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 98тЖТ  const confirmed: DecisionItem[] = [];
 99тЖТ  const provisional: DecisionItem[] = [];
100тЖТ  const contested: DecisionItem[] = [];
101тЖТ
102тЖТ  for (const d of rows) {
103тЖТ    const item: DecisionItem = {
104тЖТ      id: toRawId(d.id),
105тЖТ      summary: d.summary,
106тЖТ      status: d.status,
107тЖТ      ...(d.rationale ? { rationale: d.rationale } : {}),
108тЖТ      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
109тЖТ      ...(d.category ? { category: d.category } : {}),
110тЖТ    };
111тЖТ
112тЖТ    if (d.status === "contested") contested.push(item);
113тЖТ    else if (d.status === "provisional" || d.status === "inferred") provisional.push(item);
114тЖТ    else if (d.status === "confirmed") confirmed.push(item);
115тЖТ  }
116тЖТ
117тЖТ  return { confirmed, provisional, contested };
118тЖТ}
