120тЖТ/** Get task dependency tree (recursive) */
121тЖТexport async function getTaskDependencyTree(input: {
122тЖТ  surreal: Surreal;
123тЖТ  workspaceRecord: RecordId<"workspace", string>;
124тЖТ  taskRecord: RecordId<"task", string>;
125тЖТ}): Promise<{
126тЖТ  task: { id: string; title: string; status: string };
127тЖТ  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
128тЖТ  dependents: Array<{ id: string; title: string; status: string }>;
129тЖТ  subtasks: Array<{ id: string; title: string; status: string }>;
130тЖТ}> {
131тЖТ  const task = await input.surreal.select<TaskRow>(input.taskRecord);
132тЖТ  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
133тЖТ  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
134тЖТ    throw new Error("task is outside the current workspace scope");
135тЖТ  }
136тЖТ
137тЖТ  const query = `
138тЖТ    -- Tasks this task depends on
139тЖТ    SELECT id, title, status
140тЖТ    FROM task
141тЖТ    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
142тЖТ
143тЖТ    -- Tasks that depend on this task
144тЖТ    SELECT id, title, status
145тЖТ    FROM task
146тЖТ    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
147тЖТ
148тЖТ    -- Subtasks
149тЖТ    SELECT id, title, status
150тЖТ    FROM task
151тЖТ    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
152тЖТ    ORDER BY created_at ASC;
153тЖТ  `;
154тЖТ
155тЖТ  const results = await input.surreal
156тЖТ    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
157тЖТ    .collect<[DependencyRow[], DependencyRow[], SubtaskRow[]]>();
158тЖТ
159тЖТ  const [deps, dependents, subtasks] = results;
160тЖТ
161тЖТ  return {
162тЖТ    task: { id: toRawId(task.id), title: task.title, status: task.status },
163тЖТ    dependencies: deps.map((d) => ({
164тЖТ      id: toRawId(d.id),
165тЖТ      title: d.title,
166тЖТ      status: d.status,
167тЖТ      resolved: d.status === "done" || d.status === "completed",
168тЖТ    })),
169тЖТ    dependents: dependents.map((d) => ({ id: toRawId(d.id), title: d.title, status: d.status })),
170тЖТ    subtasks: subtasks.map((s) => ({ id: toRawId(s.id), title: s.title, status: s.status })),
171тЖТ  };
172тЖТ}
