174тЖТ/** List architecture constraints, optionally scoped to a project */
175тЖТexport async function listProjectConstraints(input: {
176тЖТ  surreal: Surreal;
177тЖТ  workspaceRecord: RecordId<"workspace", string>;
178тЖТ  projectRecord?: RecordId<"project", string>;
179тЖТ  area?: string;
180тЖТ}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
181тЖТ  // Constraints come from two sources:
182тЖТ  // 1. Decisions marked as confirmed/contested (hard constraints)
183тЖТ  // 2. Observations with severity "conflict" or "warning"
184тЖТ
185тЖТ  const areaFilter = input.area ? `AND category = $area` : "";
186тЖТ  const projectFilter = input.projectRecord
187тЖТ    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
188тЖТ    : "";
189тЖТ
190тЖТ  const query = `
191тЖТ    SELECT summary AS text, "decision" AS source_type, status, id
192тЖТ    FROM decision
193тЖТ    WHERE workspace = $workspace
194тЖТ      ${projectFilter}
195тЖТ      AND status IN ["confirmed", "contested"]
196тЖТ      ${areaFilter}
197тЖТ    ORDER BY created_at DESC LIMIT 30;
198тЖТ
199тЖТ    SELECT text, "observation" AS source_type, severity, id
200тЖТ    FROM observation
201тЖТ    WHERE workspace = $workspace
202тЖТ      AND status IN ["open", "acknowledged"]
203тЖТ      AND severity IN ["conflict", "warning"]
204тЖТ    ORDER BY created_at DESC LIMIT 20;
205тЖТ  `;
206тЖТ
207тЖТ  const results = await input.surreal
208тЖТ    .query<[Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
209тЖТ      query,
210тЖТ      {
211тЖТ        workspace: input.workspaceRecord,
212тЖТ        ...(input.projectRecord ? { project: input.projectRecord } : {}),
213тЖТ        ...(input.area ? { area: input.area } : {}),
214тЖТ      },
215тЖТ    )
216тЖТ    .collect<[Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
217тЖТ
218тЖТ  const [decisionRows, observationRows] = results;
219тЖТ
220тЖТ  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
221тЖТ
222тЖТ  for (const d of decisionRows) {
223тЖТ    constraints.push({
224тЖТ      text: d.text,
225тЖТ      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
226тЖТ      severity: d.status === "contested" ? "hard" : "hard",
227тЖТ    });
228тЖТ  }
229тЖТ
230тЖТ  for (const o of observationRows) {
231тЖТ    constraints.push({
232тЖТ      text: o.text,
233тЖТ      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
234тЖТ      severity: o.severity === "conflict" ? "hard" : "soft",
235тЖТ    });
236тЖТ  }
237тЖТ
238тЖТ  return constraints;
239тЖТ}
