241тЖТ/** List recent changes since a timestamp */
242тЖТexport async function listRecentChanges(input: {
243тЖТ  surreal: Surreal;
244тЖТ  workspaceRecord: RecordId<"workspace", string>;
245тЖТ  projectRecord?: RecordId<"project", string>;
246тЖТ  since: string;
247тЖТ}): Promise<Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>> {
248тЖТ  const sinceDate = new Date(input.since);
249тЖТ
250тЖТ  const projectFilter = input.projectRecord
251тЖТ    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
252тЖТ    : "";
253тЖТ
254тЖТ  const query = `
255тЖТ    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
256тЖТ    FROM decision
257тЖТ    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
258тЖТ    ORDER BY updated_at DESC LIMIT 20;
259тЖТ
260тЖТ    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
261тЖТ    FROM task
262тЖТ    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
263тЖТ    ORDER BY updated_at DESC LIMIT 20;
264тЖТ
265тЖТ    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
266тЖТ    FROM question
267тЖТ    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
268тЖТ    ORDER BY updated_at DESC LIMIT 20;
269тЖТ
270тЖТ    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
271тЖТ  `;
272тЖТ
273тЖТ  const results = await input.surreal
274тЖТ    .query<[null, null, null, EntityChangeRow[]]>(query, {
275тЖТ      workspace: input.workspaceRecord,
276тЖТ      since: sinceDate,
277тЖТ      ...(input.projectRecord ? { project: input.projectRecord } : {}),
278тЖТ    })
279тЖТ    .collect<[null, null, null, EntityChangeRow[]]>();
280тЖТ
281тЖТ  return (results[3] ?? []).map((r) => ({
282тЖТ    entity_type: r.entity_type,
283тЖТ    entity_name: r.entity_name,
284тЖТ    change_type: r.change_type,
285тЖТ    changed_at: toIso(r.changed_at),
286тЖТ  }));
287тЖТ}
