289тЖТ/** Create a subtask with semantic dedup */
290тЖТexport async function createSubtask(input: {
291тЖТ  surreal: Surreal;
292тЖТ  parentTaskRecord: RecordId<"task", string>;
293тЖТ  title: string;
294тЖТ  workspaceRecord: RecordId<"workspace", string>;
295тЖТ  category?: string;
296тЖТ  rationale?: string;
297тЖТ}): Promise<{ task_id: string; parent_task_id: string; already_existed: boolean }> {
298тЖТ  // Check for existing similar subtasks (semantic dedup by title)
299тЖТ  const normalizedTitle = input.title.toLowerCase().trim();
300тЖТ
301тЖТ  const [existingRows] = await input.surreal
302тЖТ    .query<[SubtaskRow[]]>(
303тЖТ      `SELECT id, title, status
304тЖТ       FROM task
305тЖТ       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent)
306тЖТ       ORDER BY created_at ASC;`,
307тЖТ      { parent: input.parentTaskRecord },
308тЖТ    )
309тЖТ    .collect<[SubtaskRow[]]>();
310тЖТ
311тЖТ  // Simple dedup: check if any existing subtask title is very similar
312тЖТ  for (const existing of existingRows) {
313тЖТ    const existingNormalized = existing.title.toLowerCase().trim();
314тЖТ    if (existingNormalized === normalizedTitle || levenshteinSimilarity(existingNormalized, normalizedTitle) > 0.85) {
315тЖТ      return {
316тЖТ        task_id: toRawId(existing.id),
317тЖТ        parent_task_id: toRawId(input.parentTaskRecord),
318тЖТ        already_existed: true,
319тЖТ      };
320тЖТ    }
321тЖТ  }
322тЖТ
323тЖТ  // Get parent task's category if not specified
324тЖТ  const parentTask = await input.surreal.select<TaskRow>(input.parentTaskRecord);
325тЖТ  if (!parentTask) throw new Error(`parent task not found: ${input.parentTaskRecord.id}`);
326тЖТ  if ((parentTask.workspace.id as string) !== (input.workspaceRecord.id as string)) {
327тЖТ    throw new Error("parent task is outside the current workspace scope");
328тЖТ  }
329тЖТ
330тЖТ  const now = new Date();
331тЖТ  const taskRecord = new RecordId("task", randomUUID());
332тЖТ
333тЖТ  await input.surreal.create(taskRecord).content({
334тЖТ    title: input.title,
335тЖТ    status: "todo",
336тЖТ    created_at: now,
337тЖТ    updated_at: now,
338тЖТ    workspace: input.workspaceRecord,
339тЖТ    ...(input.category ? { category: input.category } : parentTask.category ? { category: parentTask.category } : {}),
340тЖТ    ...(input.rationale ? { description: input.rationale } : {}),
341тЖТ  });
342тЖТ
343тЖТ  // Create subtask_of edge
344тЖТ  await input.surreal
345тЖТ    .relate(taskRecord, new RecordId("subtask_of", randomUUID()), input.parentTaskRecord, {
346тЖТ      added_at: now,
347тЖТ    })
348тЖТ    .output("after");
349тЖТ
350тЖТ  // Copy belongs_to edges from parent (inherit project/feature)
351тЖТ  const [parentBelongsTo] = await input.surreal
352тЖТ    .query<[Array<{ out: RecordId }>]>(
353тЖТ      "SELECT out FROM belongs_to WHERE `in` = $parent;",
354тЖТ      { parent: input.parentTaskRecord },
355тЖТ    )
356тЖТ    .collect<[Array<{ out: RecordId }>]>();
357тЖТ
358тЖТ  for (const edge of parentBelongsTo) {
359тЖТ    await input.surreal
360тЖТ      .relate(taskRecord, new RecordId("belongs_to", randomUUID()), edge.out, {
361тЖТ        added_at: now,
362тЖТ      })
363тЖТ      .output("after");
364тЖТ  }
365тЖТ
366тЖТ  return {
367тЖТ    task_id: toRawId(taskRecord),
368тЖТ    parent_task_id: toRawId(input.parentTaskRecord),
369тЖТ    already_existed: false,
370тЖТ  };
371тЖТ}
372тЖТ
373тЖТ/** Update task status with subtask rollup */
374тЖТexport async function updateTaskStatus(input: {
375тЖТ  surreal: Surreal;
376тЖТ  workspaceRecord: RecordId<"workspace", string>;
377тЖТ  taskRecord: RecordId<"task", string>;
378тЖТ  status: string;
379тЖТ  notes?: string;
380тЖТ}): Promise<{ task_id: string; status: string; parent_status?: string }> {
381тЖТ  const now = new Date();
382тЖТ  const task = await input.surreal.select<TaskRow>(input.taskRecord);
383тЖТ  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
384тЖТ  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
385тЖТ    throw new Error("task is outside the current workspace scope");
386тЖТ  }
387тЖТ
388тЖТ  await input.surreal.update(input.taskRecord).merge({
389тЖТ    status: input.status,
390тЖТ    updated_at: now,
391тЖТ  });
392тЖТ
393тЖТ  if (input.notes) {
394тЖТ    // Append note to description_entries
395тЖТ    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
396тЖТ    const entries = task?.description_entries ?? [];
397тЖТ    entries.push({ text: input.notes, created_at: now });
398тЖТ    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
399тЖТ  }
400тЖТ
401тЖТ  // Check if this task has a parent (subtask_of) and compute rollup
402тЖТ  const [parentRows] = await input.surreal
403тЖТ    .query<[Array<{ out: RecordId<"task", string> }>]>(
404тЖТ      "SELECT out FROM subtask_of WHERE `in` = $task LIMIT 1;",
405тЖТ      { task: input.taskRecord },
406тЖТ    )
407тЖТ    .collect<[Array<{ out: RecordId<"task", string> }>]>();
408тЖТ
409тЖТ  let parentStatus: string | undefined;
410тЖТ
411тЖТ  if (parentRows.length > 0) {
412тЖТ    const parentRecord = parentRows[0].out;
413тЖТ    parentStatus = await computeSubtaskRollup(input.surreal, parentRecord);
414тЖТ  }
415тЖТ
416тЖТ  return {
417тЖТ    task_id: toRawId(input.taskRecord),
418тЖТ    status: input.status,
419тЖТ    ...(parentStatus ? { parent_status: parentStatus } : {}),
420тЖТ  };
421тЖТ}
422тЖТ
423тЖТ/** Compute and apply subtask rollup on a parent task */
424тЖТasync function computeSubtaskRollup(
425тЖТ  surreal: Surreal,
426тЖТ  parentRecord: RecordId<"task", string>,
427тЖТ): Promise<string> {
428тЖТ  const [subtaskRows] = await surreal
429тЖТ    .query<[SubtaskRow[]]>(
430тЖТ      `SELECT id, title, status
431тЖТ       FROM task
432тЖТ       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
433тЖТ      { parent: parentRecord },
434тЖТ    )
435тЖТ    .collect<[SubtaskRow[]]>();
436тЖТ
437тЖТ  if (subtaskRows.length === 0) return "unknown";
438тЖТ
439тЖТ  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
440тЖТ  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
441тЖТ  const anyInProgress = subtaskRows.some((s) => s.status === "in_progress");
442тЖТ  const allTodo = subtaskRows.every((s) => s.status === "todo");
443тЖТ
444тЖТ  let derivedStatus: string;
445тЖТ
446тЖТ  if (allCompleted) derivedStatus = "completed";
447тЖТ  else if (anyBlocked && anyInProgress) derivedStatus = "in_progress";
448тЖТ  else if (anyBlocked) derivedStatus = "blocked";
449тЖТ  else if (anyInProgress) derivedStatus = "in_progress";
450тЖТ  else if (allTodo) derivedStatus = "todo";
451тЖТ  else derivedStatus = "in_progress";
452тЖТ
453тЖТ  await surreal.update(parentRecord).merge({
454тЖТ    status: derivedStatus,
455тЖТ    updated_at: new Date(),
456тЖТ  });
457тЖТ
458тЖТ  return derivedStatus;
459тЖТ}
