461тЖТ/** Log an implementation note on an entity */
462тЖТexport async function logImplementationNote(input: {
463тЖТ  surreal: Surreal;
464тЖТ  entityTable: string;
465тЖТ  entityId: string;
466тЖТ  note: string;
467тЖТ  filesChanged?: string[];
468тЖТ}): Promise<{ entity_id: string; note_added: boolean }> {
469тЖТ  const record = new RecordId(input.entityTable, input.entityId);
470тЖТ  const entity = await input.surreal.select<{ description_entries?: Array<{ text: string; source?: RecordId; created_at: Date }> }>(record);
471тЖТ
472тЖТ  if (!entity) throw new Error(`entity not found: ${input.entityTable}:${input.entityId}`);
473тЖТ
474тЖТ  const now = new Date();
475тЖТ  const entries = entity.description_entries ?? [];
476тЖТ  const noteText = input.filesChanged?.length
477тЖТ    ? `${input.note}\n\nFiles: ${input.filesChanged.join(", ")}`
478тЖТ    : input.note;
479тЖТ
480тЖТ  entries.push({ text: noteText, created_at: now });
481тЖТ
482тЖТ  await input.surreal.update(record).merge({
483тЖТ    description_entries: entries,
484тЖТ    updated_at: now,
485тЖТ  });
486тЖТ
487тЖТ  return { entity_id: `${input.entityTable}:${input.entityId}`, note_added: true };
488тЖТ}
