490тЖТ/** Create or finalize an agent session */
491тЖТexport async function createAgentSession(input: {
492тЖТ  surreal: Surreal;
493тЖТ  agent: string;
494тЖТ  workspaceRecord: RecordId<"workspace", string>;
495тЖТ  projectRecord?: RecordId<"project", string>;
496тЖТ  taskId?: string;
497тЖТ}): Promise<{ session_id: string }> {
498тЖТ  const now = new Date();
499тЖТ  const sessionRecord = new RecordId("agent_session", randomUUID());
500тЖТ
501тЖТ  await input.surreal.create(sessionRecord).content({
502тЖТ    agent: input.agent,
503тЖТ    started_at: now,
504тЖТ    workspace: input.workspaceRecord,
505тЖТ    created_at: now,
506тЖТ    ...(input.projectRecord ? { project: input.projectRecord } : {}),
507тЖТ    ...(input.taskId ? { task_id: new RecordId("task", requireRawId(input.taskId, "task_id")) } : {}),
508тЖТ  });
509тЖТ
510тЖТ  // If task-scoped, link session to task and auto-promote status
511тЖТ  if (input.taskId) {
512тЖТ    const taskRecord = new RecordId("task", requireRawId(input.taskId, "task_id"));
513тЖТ    const task = await input.surreal.select<TaskRow>(taskRecord);
514тЖТ    if (!task) {
515тЖТ      throw new Error(`task not found: ${input.taskId}`);
516тЖТ    }
517тЖТ    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
518тЖТ      throw new Error("task is outside the current workspace scope");
519тЖТ    }
520тЖТ    await input.surreal.update(taskRecord).merge({
521тЖТ      ...(task.status === "todo" || task.status === "ready"
522тЖТ        ? { status: "in_progress" }
523тЖТ        : {}),
524тЖТ      source_session: sessionRecord,
525тЖТ      updated_at: now,
526тЖТ    });
527тЖТ  }
528тЖТ
529тЖТ  return { session_id: toRawId(sessionRecord) };
530тЖТ}
