532тЖТ/** End an agent session with summary */
533тЖТexport async function endAgentSession(input: {
534тЖТ  surreal: Surreal;
535тЖТ  workspaceRecord: RecordId<"workspace", string>;
536тЖТ  sessionId: string;
537тЖТ  summary: string;
538тЖТ  decisionsMade?: string[];
539тЖТ  questionsAsked?: string[];
540тЖТ  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
541тЖТ  filesChanged?: Array<{ path: string; change_type: string }>;
542тЖТ  observationsLogged?: string[];
543тЖТ}): Promise<{ session_id: string; ended: boolean }> {
544тЖТ  const now = new Date();
545тЖТ  const sessionRecord = new RecordId("agent_session", requireRawId(input.sessionId, "session_id"));
546тЖТ  const session = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(sessionRecord);
547тЖТ  if (!session) {
548тЖТ    throw new Error(`session not found: ${input.sessionId}`);
549тЖТ  }
550тЖТ  if ((session.workspace.id as string) !== (input.workspaceRecord.id as string)) {
551тЖТ    throw new Error("session is outside the current workspace scope");
552тЖТ  }
553тЖТ
554тЖТ  await input.surreal.update(sessionRecord).merge({
555тЖТ    ended_at: now,
556тЖТ    summary: input.summary,
557тЖТ    ...(input.decisionsMade?.length
558тЖТ      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", requireRawId(id, "decisions_made[]"))) }
559тЖТ      : {}),
560тЖТ    ...(input.questionsAsked?.length
561тЖТ      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", requireRawId(id, "questions_asked[]"))) }
562тЖТ      : {}),
563тЖТ    ...(input.tasksProgressed?.length
564тЖТ      ? {
565тЖТ          tasks_progressed: input.tasksProgressed.map((t) => ({
566тЖТ            task_id: new RecordId("task", requireRawId(t.task_id, "tasks_progressed[].task_id")),
567тЖТ            from_status: t.from_status,
568тЖТ            to_status: t.to_status,
569тЖТ          })),
570тЖТ        }
571тЖТ      : {}),
572тЖТ    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
573тЖТ    ...(input.observationsLogged?.length
574тЖТ      ? { observations_logged: input.observationsLogged.map((id) => new RecordId("observation", requireRawId(id, "observations_logged[]"))) }
575тЖТ      : {}),
576тЖТ  });
577тЖТ
578тЖТ  // Create session -> entity edges
579тЖТ  if (input.decisionsMade?.length) {
580тЖТ    for (const decisionId of input.decisionsMade) {
581тЖТ      const rawDecisionId = requireRawId(decisionId, "decisions_made[]");
582тЖТ      await input.surreal
583тЖТ        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", rawDecisionId), {
584тЖТ          added_at: now,
585тЖТ        })
586тЖТ        .output("after");
587тЖТ    }
588тЖТ  }
589тЖТ
590тЖТ  if (input.questionsAsked?.length) {
591тЖТ    for (const questionId of input.questionsAsked) {
592тЖТ      const rawQuestionId = requireRawId(questionId, "questions_asked[]");
593тЖТ      await input.surreal
594тЖТ        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", rawQuestionId), {
595тЖТ          added_at: now,
596тЖТ        })
597тЖТ        .output("after");
598тЖТ    }
599тЖТ  }
600тЖТ
601тЖТ  if (input.tasksProgressed?.length) {
602тЖТ    for (const t of input.tasksProgressed) {
603тЖТ      const rawTaskId = requireRawId(t.task_id, "tasks_progressed[].task_id");
604тЖТ      await input.surreal
605тЖТ        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", rawTaskId), {
606тЖТ          from_status: t.from_status,
607тЖТ          to_status: t.to_status,
608тЖТ          added_at: now,
609тЖТ        })
610тЖТ        .output("after");
611тЖТ    }
612тЖТ  }
613тЖТ
614тЖТ  return { session_id: toRawId(sessionRecord), ended: true };
615тЖТ}
