617тЖТ/** Log a git commit to the graph */
618тЖТexport async function logCommit(input: {
619тЖТ  surreal: Surreal;
620тЖТ  workspaceRecord: RecordId<"workspace", string>;
621тЖТ  projectRecord?: RecordId<"project", string>;
622тЖТ  sha: string;
623тЖТ  message: string;
624тЖТ  author: string;
625тЖТ  taskUpdates?: Array<{ task_id: string; new_status: string }>;
626тЖТ  relatedTaskIds?: string[];
627тЖТ  decisionsDetected?: Array<{ name: string; rationale: string }>;
628тЖТ}): Promise<{ commit_id: string; tasks_updated: number; tasks_linked: number; decisions_created: number }> {
629тЖТ  const now = new Date();
630тЖТ  const commitRecord = new RecordId("git_commit", randomUUID());
631тЖТ
632тЖТ  await input.surreal.create(commitRecord).content({
633тЖТ    sha: input.sha,
634тЖТ    message: input.message,
635тЖТ    author_name: input.author,
636тЖТ    workspace: input.workspaceRecord,
637тЖТ    authored_at: now,
638тЖТ    created_at: now,
639тЖТ  });
640тЖТ
641тЖТ  // Update task statuses
642тЖТ  let tasksUpdated = 0;
643тЖТ  if (input.taskUpdates?.length) {
644тЖТ    for (const update of input.taskUpdates) {
645тЖТ      const taskRecord = new RecordId("task", requireRawId(update.task_id, "task_updates[].task_id"));
646тЖТ      const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
647тЖТ      if (!task) {
648тЖТ        throw new Error(`task not found: ${update.task_id}`);
649тЖТ      }
650тЖТ      if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
651тЖТ        throw new Error("task update is outside the current workspace scope");
652тЖТ      }
653тЖТ      await input.surreal.update(taskRecord).merge({
654тЖТ        status: update.new_status,
655тЖТ        updated_at: now,
656тЖТ      });
657тЖТ      tasksUpdated++;
658тЖТ    }
659тЖТ  }
660тЖТ
661тЖТ  // Link related tasks to this commit
662тЖТ  const linkedTaskIds = new Set<string>();
663тЖТ  // Include tasks from task_updates
664тЖТ  if (input.taskUpdates?.length) {
665тЖТ    for (const update of input.taskUpdates) {
666тЖТ      linkedTaskIds.add(requireRawId(update.task_id, "task_updates[].task_id"));
667тЖТ    }
668тЖТ  }
669тЖТ  // Include explicitly declared related tasks
670тЖТ  if (input.relatedTaskIds?.length) {
671тЖТ    for (const taskId of input.relatedTaskIds) {
672тЖТ      linkedTaskIds.add(requireRawId(taskId, "related_task_ids[]"));
673тЖТ    }
674тЖТ  }
675тЖТ  for (const taskId of linkedTaskIds) {
676тЖТ    const taskRecord = new RecordId("task", taskId);
677тЖТ    const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
678тЖТ    if (!task) {
679тЖТ      throw new Error(`task not found: ${taskId}`);
680тЖТ    }
681тЖТ    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
682тЖТ      throw new Error("task link is outside the current workspace scope");
683тЖТ    }
684тЖТ    await input.surreal
685тЖТ      .relate(taskRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
686тЖТ        commit_sha: input.sha,
687тЖТ        linked_at: now,
688тЖТ      })
689тЖТ      .output("after");
690тЖТ  }
691тЖТ
692тЖТ  // Create provisional decisions if flagged
693тЖТ  let decisionsCreated = 0;
694тЖТ  if (input.decisionsDetected?.length) {
695тЖТ    for (const decision of input.decisionsDetected) {
696тЖТ      const decisionRecord = new RecordId("decision", randomUUID());
697тЖТ      await input.surreal.create(decisionRecord).content({
698тЖТ        summary: decision.name,
699тЖТ        rationale: decision.rationale,
700тЖТ        status: "provisional",
701тЖТ        decided_by_name: "code-agent",
702тЖТ        workspace: input.workspaceRecord,
703тЖТ        source_commit: commitRecord,
704тЖТ        created_at: now,
705тЖТ        updated_at: now,
706тЖТ      });
707тЖТ
708тЖТ      // Link decision to project (if known)
709тЖТ      if (input.projectRecord) {
710тЖТ        await input.surreal
711тЖТ          .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
712тЖТ            added_at: now,
713тЖТ          })
714тЖТ          .output("after");
715тЖТ      }
716тЖТ
717тЖТ      // Create implemented_by edge
718тЖТ      await input.surreal
719тЖТ        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
720тЖТ          commit_sha: input.sha,
721тЖТ          linked_at: now,
722тЖТ        })
723тЖТ        .output("after");
724тЖТ
725тЖТ      decisionsCreated++;
726тЖТ    }
727тЖТ  }
728тЖТ
729тЖТ  return {
730тЖТ    commit_id: toRawId(commitRecord),
731тЖТ    tasks_updated: tasksUpdated,
732тЖТ    tasks_linked: linkedTaskIds.size,
733тЖТ    decisions_created: decisionsCreated,
734тЖТ  };
735тЖТ}
