737тЖТ// ---------------------------------------------------------------------------
738тЖТ// Utility
739тЖТ// ---------------------------------------------------------------------------
740тЖТ
741тЖТfunction levenshteinSimilarity(a: string, b: string): number {
742тЖТ  if (a === b) return 1;
743тЖТ  const longer = a.length > b.length ? a : b;
744тЖТ  const shorter = a.length > b.length ? b : a;
745тЖТ  if (longer.length === 0) return 1;
746тЖТ
747тЖТ  const costs: number[] = [];
748тЖТ  for (let i = 0; i <= longer.length; i++) {
749тЖТ    let lastValue = i;
750тЖТ    for (let j = 0; j <= shorter.length; j++) {
751тЖТ      if (i === 0) {
752тЖТ        costs[j] = j;
753тЖТ      } else if (j > 0) {
754тЖТ        let newValue = costs[j - 1];
755тЖТ        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
756тЖТ          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
757тЖТ        }
758тЖТ        costs[j - 1] = lastValue;
759тЖТ        lastValue = newValue;
760тЖТ      }
761тЖТ    }
762тЖТ    if (i > 0) costs[shorter.length] = lastValue;
763тЖТ  }
764тЖТ
765тЖТ  return (longer.length - costs[shorter.length]) / longer.length;
766тЖТ}
