471тЖТ    AND extraction_confidence != NONE
472тЖТ    AND string::contains(string::lowercase(summary), $query)
473тЖТ  ORDER BY created_at DESC
474тЖТ  LIMIT $safe_limit;
475тЖТ
476тЖТ  LET $question_rows = SELECT
