 1тЖТimport { execSync } from "node:child_process";
 2тЖТimport { requireConfig } from "../config";
 3тЖТimport { BrainHttpClient } from "../http-client";
 4тЖТ
 5тЖТ/**
 6тЖТ * brain check-commit
 7тЖТ * Called by pre-commit git hook.
 8тЖТ * Reads staged diff and checks for task completion, unlogged decisions, constraint violations.
 9тЖТ */
10тЖТexport async function runCheckCommit(): Promise<void> {
11тЖТ  const config = await requireConfig();
12тЖТ  const client = new BrainHttpClient(config);
13тЖТ  const cwd = process.cwd();
14тЖТ
15тЖТ  let diff: string;
16тЖТ  let commitMessage: string;
17тЖТ  try {
18тЖТ    diff = execSync("git diff --cached", { encoding: "utf-8", cwd }).trim();
19тЖТ    try {
20тЖТ      commitMessage = execSync("cat .git/COMMIT_EDITMSG", { encoding: "utf-8", cwd }).trim();
21тЖТ    } catch {
22тЖТ      commitMessage = "";
23тЖТ    }
24тЖТ  } catch {
25тЖТ    return; // Not in a git repo or no staged changes
26тЖТ  }
27тЖТ
28тЖТ  if (!diff) return;
29тЖТ
30тЖТ  try {
31тЖТ    // Truncate for token budget
32тЖТ    const truncatedDiff = diff.length > 8000 ? diff.slice(0, 8000) : diff;
33тЖТ
34тЖТ    const result = await client.checkCommit({
35тЖТ      diff: truncatedDiff,
36тЖТ      commit_message: commitMessage,
37тЖТ    });
38тЖТ
39тЖТ    // Display findings to stderr (stdout is reserved for git hook protocol)
40тЖТ    for (const tc of result.task_completions) {
41тЖТ      if (tc.confidence >= 0.6) {
42тЖТ        process.stderr.write(`Brain: This commit may complete: ${tc.task_title}\n`);
43тЖТ      }
44тЖТ    }
45тЖТ    for (const d of result.unlogged_decisions) {
46тЖТ      process.stderr.write(`Brain: Unlogged decision: ${d.description}\n`);
47тЖТ    }
48тЖТ    for (const v of result.constraint_violations) {
49тЖТ      process.stderr.write(`Brain: Constraint violation (${v.severity}): ${v.violation}\n`);
50тЖТ    }
51тЖТ  } catch {
52тЖТ    // Never block commits on analysis failures
53тЖТ  }
54тЖТ}
