 42тЖТfunction formatWorkspaceOverview(overview: WorkspaceOverviewResponse): string {
 43тЖТ  const lines: string[] = [];
 44тЖТ
 45тЖТ  lines.push(`# Brain Workspace: ${overview.workspace.name}\n`);
 46тЖТ
 47тЖТ  if (overview.projects.length === 0) {
 48тЖТ    lines.push("No projects found. Create one in the Brain web UI.");
 49тЖТ    return lines.join("\n");
 50тЖТ  }
 51тЖТ
 52тЖТ  lines.push("## Projects");
 53тЖТ  for (const p of overview.projects) {
 54тЖТ    const c = p.counts;
 55тЖТ    const counts = `${c.tasks}T ${c.decisions}D ${c.features}F ${c.questions}Q`;
 56тЖТ    lines.push(`  - ${p.name} (id: ${p.id}) [${counts}]`);
 57тЖТ  }
 58тЖТ  lines.push("");
 59тЖТ
 60тЖТ  const { contested_decisions, open_observations, pending_suggestions } = overview.hot_items;
 61тЖТ
 62тЖТ  if (contested_decisions.length > 0) {
 63тЖТ    lines.push("## Contested Decisions");
 64тЖТ    for (const d of contested_decisions) {
 65тЖТ      lines.push(`  - ${d.summary} (id: ${d.id})`);
 66тЖТ    }
 67тЖТ    lines.push("");
 68тЖТ  }
 69тЖТ
 70тЖТ  if (open_observations.length > 0) {
 71тЖТ    lines.push("## Open Observations");
 72тЖТ    for (const o of open_observations) {
 73тЖТ      lines.push(`  - [${o.severity}] ${o.text}`);
 74тЖТ    }
 75тЖТ    lines.push("");
 76тЖТ  }
 77тЖТ
 78тЖТ  if (pending_suggestions.length > 0) {
 79тЖТ    lines.push("## Pending Suggestions");
 80тЖТ    for (const s of pending_suggestions) {
 81тЖТ      lines.push(`  - [${s.category}] ${s.text}`);
 82тЖТ    }
 83тЖТ    lines.push("");
 84тЖТ  }
 85тЖТ
 86тЖТ  if (overview.active_sessions.length > 0) {
 87тЖТ    lines.push("## Active Agent Sessions");
 88тЖТ    for (const s of overview.active_sessions) {
 89тЖТ      const taskInfo = s.task ? ` on "${s.task.title}"` : "";
 90тЖТ      lines.push(`  - ${s.agent}${taskInfo}`);
 91тЖТ    }
 92тЖТ    lines.push("");
 93тЖТ  }
 94тЖТ
 95тЖТ  lines.push("Use `get_workspace_context`, `get_project_context`, or `get_task_context` MCP tools for more detail.");
 96тЖТ
 97тЖТ  return lines.join("\n");
 98тЖТ}
