104тЖТexport async function runCheckUpdates(): Promise<void> {
105тЖТ  const config = await requireConfig();
106тЖТ  const client = new BrainHttpClient(config);
107тЖТ
108тЖТ  try {
109тЖТ    const since = new Date(Date.now() - 5 * 60_000).toISOString();
110тЖТ    const result = (await client.getChanges({ since })) as {
111тЖТ      changes: Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>;
112тЖТ    };
113тЖТ
114тЖТ    if (!result.changes || result.changes.length === 0) return;
115тЖТ
116тЖТ    const critical = result.changes.filter(
117тЖТ      (c) => c.change_type === "contested" || c.change_type === "superseded",
118тЖТ    );
119тЖТ    if (critical.length > 0) {
120тЖТ      console.log("\n--- Context Update ---");
121тЖТ      for (const c of critical) {
122тЖТ        console.log(`[${c.entity_type}] ${c.entity_name} тАФ ${c.change_type} at ${c.changed_at}`);
123тЖТ      }
124тЖТ      console.log("--- End Update ---\n");
125тЖТ    }
126тЖТ
127тЖТ    const crossAgent = result.changes.filter(
128тЖТ      (c) =>
129тЖТ        c.change_type === "provisional" ||
130тЖТ        (c.entity_type === "observation" && (c.change_type === "warning" || c.change_type === "conflict")),
131тЖТ    );
132тЖТ    if (crossAgent.length > 0) {
133тЖТ      console.log("\n--- Cross-Agent Activity ---");
134тЖТ      for (const c of crossAgent) {
135тЖТ        console.log(`[${c.entity_type}] ${c.entity_name} тАФ ${c.change_type}`);
136тЖТ      }
137тЖТ      console.log("--- End ---\n");
138тЖТ    }
139тЖТ
140тЖТ    const newSuggestions = result.changes.filter(
141тЖТ      (c) => c.entity_type === "suggestion" && c.change_type === "pending",
142тЖТ    );
143тЖТ    if (newSuggestions.length > 0) {
144тЖТ      console.log("\n--- New Suggestions ---");
145тЖТ      for (const s of newSuggestions) {
146тЖТ        console.log(`[suggestion] ${s.entity_name}`);
147тЖТ      }
148тЖТ      console.log("--- End ---\n");
149тЖТ    }
150тЖТ  } catch {
151тЖТ    // Silent on error тАФ don't block the user
152тЖТ  }
153тЖТ}
