155тЖТ/**
156тЖТ * brain system end-session
157тЖТ * Called by SessionEnd hook. Reads the Stop hook JSON from stdin which includes
158тЖТ * project_id (set by the agent) and session summary.
159тЖТ */
160тЖТexport async function runEndSession(): Promise<void> {
161тЖТ  const config = await requireConfig();
162тЖТ  const client = new BrainHttpClient(config);
163тЖТ
164тЖТ  try {
165тЖТ    // Read stdin (Claude Code pipes Stop hook JSON)
166тЖТ    let stdinText = "";
167тЖТ    try {
168тЖТ      const chunks: Buffer[] = [];
169тЖТ      for await (const chunk of Bun.stdin.stream()) {
170тЖТ        chunks.push(Buffer.from(chunk));
171тЖТ      }
172тЖТ      stdinText = Buffer.concat(chunks).toString("utf-8").trim();
173тЖТ    } catch {
174тЖТ      // stdin not available or empty
175тЖТ    }
176тЖТ
177тЖТ    if (!stdinText) return;
178тЖТ
179тЖТ    const parsed = JSON.parse(stdinText) as Record<string, unknown>;
180тЖТ
181тЖТ    if (parsed.decision === "block") {
182тЖТ      const reason = typeof parsed.reason === "string" ? parsed.reason : "Stop hook returned block decision";
183тЖТ      throw new Error(`Session end blocked: ${reason}`);
184тЖТ    }
185тЖТ    if (parsed.decision !== "approve") {
186тЖТ      throw new Error("Stop hook payload must include decision=\"approve\" or decision=\"block\"");
187тЖТ    }
188тЖТ    if (typeof parsed.summary !== "string" || parsed.summary.trim().length === 0) {
189тЖТ      throw new Error("Stop hook payload must include a non-empty string summary");
190тЖТ    }
191тЖТ
192тЖТ    // project_id comes from the agent via the Stop hook payload (optional)
193тЖТ    const projectId = typeof parsed.project_id === "string" ? parsed.project_id : undefined;
194тЖТ    const summary = parsed.summary.trim();
195тЖТ
196тЖТ    const parseStringArray = (key: string): string[] | undefined => {
197тЖТ      const val = parsed[key];
198тЖТ      if (val === undefined) return undefined;
199тЖТ      if (!Array.isArray(val) || !val.every((v) => typeof v === "string")) {
200тЖТ        throw new Error(`${key} must be an array of strings`);
201тЖТ      }
202тЖТ      return val;
203тЖТ    };
204тЖТ
205тЖТ    const decisionsMade = parseStringArray("decisions_made");
206тЖТ    const questionsAsked = parseStringArray("questions_asked");
207тЖТ    const observationsLogged = parseStringArray("observations_logged");
208тЖТ    const subtasksCreated = parseStringArray("subtasks_created");
209тЖТ    const suggestionsCreated = parseStringArray("suggestions_created");
210тЖТ
211тЖТ    let tasksProgressed: Array<{ task_id: string; from_status: string; to_status: string }> | undefined;
212тЖТ    if (parsed.tasks_progressed !== undefined) {
213тЖТ      if (!Array.isArray(parsed.tasks_progressed)) throw new Error("tasks_progressed must be an array");
214тЖТ      tasksProgressed = parsed.tasks_progressed.map((entry) => {
215тЖТ        const row = entry as Record<string, unknown>;
216тЖТ        if (typeof row.task_id !== "string" || typeof row.from_status !== "string" || typeof row.to_status !== "string") {
217тЖТ          throw new Error("tasks_progressed entries must include string task_id, from_status, and to_status");
218тЖТ        }
219тЖТ        return { task_id: row.task_id, from_status: row.from_status, to_status: row.to_status };
220тЖТ      });
221тЖТ    }
222тЖТ
223тЖТ    let filesChanged: Array<{ path: string; change_type: string }> | undefined;
224тЖТ    if (parsed.files_changed !== undefined) {
225тЖТ      if (!Array.isArray(parsed.files_changed)) throw new Error("files_changed must be an array");
226тЖТ      filesChanged = parsed.files_changed.map((entry) => {
227тЖТ        const row = entry as Record<string, unknown>;
228тЖТ        if (typeof row.path !== "string" || typeof row.change_type !== "string") {
229тЖТ          throw new Error("files_changed entries must include string path and change_type");
230тЖТ        }
231тЖТ        return { path: row.path, change_type: row.change_type };
232тЖТ      });
233тЖТ    }
234тЖТ
235тЖТ    // Create session and immediately end it with summary
236тЖТ    const session = await client.sessionStart({
237тЖТ      agent: "claude-code",
238тЖТ      ...(projectId ? { project_id: projectId } : {}),
239тЖТ    });
240тЖТ
241тЖТ    await client.sessionEnd({
242тЖТ      session_id: session.session_id,
243тЖТ      summary,
244тЖТ      decisions_made: decisionsMade,
245тЖТ      questions_asked: questionsAsked,
246тЖТ      tasks_progressed: tasksProgressed,
247тЖТ      files_changed: filesChanged,
248тЖТ      observations_logged: observationsLogged,
249тЖТ      subtasks_created: subtasksCreated,
250тЖТ      suggestions_created: suggestionsCreated,
251тЖТ    });
252тЖТ  } catch (error) {
253тЖТ    console.error(`Brain: Failed to end session: ${error instanceof Error ? error.message : error}`);
254тЖТ  }
255тЖТ}
