162тЖТ/** Build a lightweight workspace overview for agent orientation */
163тЖТexport async function buildWorkspaceOverview(input: {
164тЖТ  surreal: Surreal;
165тЖТ  workspaceRecord: RecordId<"workspace", string>;
166тЖТ  workspaceName: string;
167тЖТ  excludeSessionId?: string;
168тЖТ}): Promise<WorkspaceOverview> {
169тЖТ  const { surreal, workspaceRecord, workspaceName } = input;
170тЖТ
171тЖТ  const overviewQuery = `
172тЖТ    SELECT id, name, status, description
173тЖТ    FROM project
174тЖТ    WHERE id IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace);
175тЖТ
176тЖТ    SELECT out AS project_id, record::tb(\`in\`) AS entity_type, count() AS count
177тЖТ    FROM belongs_to
178тЖТ    WHERE out IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace)
179тЖТ    GROUP BY project_id, entity_type;
180тЖТ
181тЖТ    SELECT \`in\` AS project_id, count() AS count
182тЖТ    FROM has_feature
183тЖТ    WHERE \`in\` IN (SELECT VALUE out FROM has_project WHERE \`in\` = $workspace)
184тЖТ    GROUP BY project_id;
185тЖТ  `;
186тЖТ
187тЖТ  const [projectRows, entityCounts, featureCounts] = await surreal
188тЖТ    .query<[ProjectRow[], EntityCountRow[], FeatureCountRow[]]>(overviewQuery, {
189тЖТ      workspace: workspaceRecord,
190тЖТ    })
191тЖТ    .collect<[ProjectRow[], EntityCountRow[], FeatureCountRow[]]>();
192тЖТ
193тЖТ  const countsByProject = buildProjectCountMaps(entityCounts, featureCounts);
194тЖТ  const hotItems = await loadHotItems(surreal, workspaceRecord);
195тЖТ  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, undefined, input.excludeSessionId);
196тЖТ
197тЖТ  return {
198тЖТ    workspace: { id: workspaceRecord.id as string, name: workspaceName },
199тЖТ    projects: projectRows.map((p) => ({
200тЖТ      id: toRawId(p.id),
201тЖТ      name: p.name,
202тЖТ      status: p.status,
203тЖТ      ...(p.description ? { description: p.description } : {}),
204тЖТ      counts: countsByProject.get(toRawId(p.id)) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 },
205тЖТ    })),
206тЖТ    hot_items: hotItems,
207тЖТ    active_sessions: activeSessions,
208тЖТ  };
209тЖТ}
210тЖТ
211тЖТfunction buildProjectCountMaps(
212тЖТ  entityCounts: EntityCountRow[],
213тЖТ  featureCounts: FeatureCountRow[],
214тЖТ): Map<string, { tasks: number; decisions: number; features: number; questions: number }> {
215тЖТ  const map = new Map<string, { tasks: number; decisions: number; features: number; questions: number }>();
216тЖТ
217тЖТ  for (const row of entityCounts) {
218тЖТ    const pid = toRawId(row.project_id);
219тЖТ    const entry = map.get(pid) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 };
220тЖТ    if (row.entity_type === "task") entry.tasks = row.count;
221тЖТ    else if (row.entity_type === "decision") entry.decisions = row.count;
222тЖТ    else if (row.entity_type === "question") entry.questions = row.count;
223тЖТ    map.set(pid, entry);
224тЖТ  }
225тЖТ
226тЖТ  for (const row of featureCounts) {
227тЖТ    const pid = toRawId(row.project_id);
228тЖТ    const entry = map.get(pid) ?? { tasks: 0, decisions: 0, features: 0, questions: 0 };
229тЖТ    entry.features = row.count;
230тЖТ    map.set(pid, entry);
231тЖТ  }
232тЖТ
233тЖТ  return map;
234тЖТ}
235тЖТ
236тЖТ// ===========================================================================
237тЖТ// 2. Project Context (full project context, project_id required)
238тЖТ// ===========================================================================
239тЖТ
240тЖТ/** Build a full project context packet (decisions, tasks, questions, observations, suggestions) */
241тЖТexport async function buildProjectContext(input: {
242тЖТ  surreal: Surreal;
243тЖТ  workspaceRecord: RecordId<"workspace", string>;
244тЖТ  workspaceName: string;
245тЖТ  projectRecord: RecordId<"project", string>;
246тЖТ  taskId?: string;
247тЖТ  since?: string;
248тЖТ  excludeSessionId?: string;
249тЖТ}): Promise<ContextPacket> {
250тЖТ  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
251тЖТ
252тЖТ  const project = await surreal.select<ProjectRow>(projectRecord);
253тЖТ  if (!project) {
254тЖТ    throw new Error(`project not found: ${projectRecord.id}`);
255тЖТ  }
256тЖТ
257тЖТ  const projectEntitiesQuery = `
258тЖТ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
259тЖТ
260тЖТ    SELECT id, summary, status, rationale, decided_at, category, priority
261тЖТ    FROM decision
262тЖТ    WHERE workspace = $workspace AND id IN $project_entity_ids
263тЖТ    ORDER BY created_at DESC LIMIT 50;
264тЖТ
265тЖТ    SELECT id, title, status, priority, category, description, source_session
266тЖТ    FROM task
267тЖТ    WHERE workspace = $workspace AND id IN $project_entity_ids
268тЖТ    ORDER BY created_at DESC LIMIT 50;
269тЖТ
270тЖТ    SELECT id, text, status, context, priority
271тЖТ    FROM question
272тЖТ    WHERE workspace = $workspace AND id IN $project_entity_ids
273тЖТ    ORDER BY created_at DESC LIMIT 30;
274тЖТ
275тЖТ    SELECT id, text, severity, status, category, observation_type
276тЖТ    FROM observation
277тЖТ    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
278тЖТ    ORDER BY created_at DESC LIMIT 20;
279тЖТ
280тЖТ    SELECT id, text, category, rationale, confidence, status, suggested_by, created_at
281тЖТ    FROM suggestion
282тЖТ    WHERE workspace = $workspace AND status IN ["pending", "deferred"]
283тЖТ    ORDER BY confidence DESC, created_at DESC LIMIT 15;
284тЖТ  `;
285тЖТ
286тЖТ  const results = await surreal
287тЖТ    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[], SuggestionRow[]]>(projectEntitiesQuery, {
288тЖТ      project: projectRecord,
289тЖТ      workspace: workspaceRecord,
290тЖТ    })
291тЖТ    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[], SuggestionRow[]]>();
292тЖТ
293тЖТ  const [, decisionRows, taskRows, questionRows, observationRows, suggestionRows] = results;
294тЖТ
295тЖТ  // Categorize decisions by status
296тЖТ  const confirmed: DecisionContext[] = [];
297тЖТ  const provisional: DecisionContext[] = [];
298тЖТ  const contested: DecisionContext[] = [];
299тЖТ
300тЖТ  for (const d of decisionRows) {
301тЖТ    const ctx: DecisionContext = {
302тЖТ      id: toRawId(d.id),
303тЖТ      summary: d.summary,
304тЖТ      status: d.status,
305тЖТ      ...(d.rationale ? { rationale: d.rationale } : {}),
306тЖТ      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
307тЖТ      ...(d.category ? { category: d.category } : {}),
308тЖТ      ...(d.priority ? { priority: d.priority } : {}),
309тЖТ    };
310тЖТ
311тЖТ    if (d.status === "contested") {
312тЖТ      contested.push(ctx);
313тЖТ    } else if (d.status === "provisional" || d.status === "inferred") {
314тЖТ      provisional.push(ctx);
315тЖТ    } else if (d.status === "confirmed") {
316тЖТ      confirmed.push(ctx);
317тЖТ    }
318тЖТ  }
319тЖТ
320тЖТ  const activeTasks: TaskContext[] = taskRows
321тЖТ    .filter((t) => t.status !== "done" && t.status !== "completed")
322тЖТ    .map((t) => ({
323тЖТ      id: toRawId(t.id),
324тЖТ      title: t.title,
325тЖТ      status: t.status,
326тЖТ      ...(t.priority ? { priority: t.priority } : {}),
327тЖТ      ...(t.category ? { category: t.category } : {}),
328тЖТ      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
329тЖТ    }));
330тЖТ
331тЖТ  const openQuestions: QuestionContext[] = questionRows
332тЖТ    .filter((q) => q.status !== "answered" && q.status !== "resolved")
333тЖТ    .map((q) => ({
334тЖТ      id: toRawId(q.id),
335тЖТ      text: q.text,
336тЖТ      status: q.status,
337тЖТ      ...(q.context ? { context: q.context } : {}),
338тЖТ      ...(q.priority ? { priority: q.priority } : {}),
339тЖТ    }));
340тЖТ
341тЖТ  const observations: ObservationContext[] = observationRows.map((o) => ({
342тЖТ    id: toRawId(o.id),
343тЖТ    text: o.text,
344тЖТ    severity: o.severity,
345тЖТ    status: o.status,
346тЖТ    ...(o.category ? { category: o.category } : {}),
347тЖТ    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
348тЖТ  }));
349тЖТ
350тЖТ  const pendingSuggestions: SuggestionContext[] = suggestionRows.map((s) => ({
351тЖТ    id: toRawId(s.id),
352тЖТ    text: s.text,
353тЖТ    category: s.category,
354тЖТ    rationale: s.rationale,
355тЖТ    confidence: s.confidence,
356тЖТ    status: s.status,
357тЖТ    suggested_by: s.suggested_by,
358тЖТ    created_at: toIso(s.created_at),
359тЖТ  }));
360тЖТ
361тЖТ  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, projectRecord, input.excludeSessionId);
362тЖТ
363тЖТ  const recentChanges: RecentChangeContext[] = input.since
364тЖТ    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
365тЖТ    : [];
366тЖТ
367тЖТ  let taskScope: TaskScopeContext | undefined;
368тЖТ  if (taskId) {
369тЖТ    taskScope = await buildTaskScope(surreal, workspaceRecord, taskId);
370тЖТ  }
371тЖТ
372тЖТ  return {
373тЖТ    workspace: { id: workspaceRecord.id as string, name: workspaceName },
374тЖТ    project: {
375тЖТ      id: projectRecord.id as string,
376тЖТ      name: project.name,
377тЖТ      status: project.status,
378тЖТ      ...(project.description ? { description: project.description } : {}),
379тЖТ    },
380тЖТ    ...(taskScope ? { task_scope: taskScope } : {}),
381тЖТ    decisions: { confirmed, provisional, contested },
382тЖТ    active_tasks: activeTasks,
383тЖТ    open_questions: openQuestions,
384тЖТ    recent_changes: recentChanges,
385тЖТ    observations,
386тЖТ    pending_suggestions: pendingSuggestions,
387тЖТ    active_sessions: activeSessions,
388тЖТ  };
389тЖТ}
390тЖТ
391тЖТ// ===========================================================================
392тЖТ// 3. Task Context (task-focused, task_id required, project resolved from graph)
393тЖТ// ===========================================================================
394тЖТ
395тЖТ/** Build task-focused context: task subgraph + project hot items */
396тЖТexport async function buildTaskContext(input: {
397тЖТ  surreal: Surreal;
398тЖТ  workspaceRecord: RecordId<"workspace", string>;
399тЖТ  workspaceName: string;
400тЖТ  taskId: string;
401тЖТ  excludeSessionId?: string;
402тЖТ}): Promise<TaskContextPacket> {
403тЖТ  const { surreal, workspaceRecord, workspaceName, taskId } = input;
404тЖТ
405тЖТ  const taskRecord = new RecordId("task", taskId);
406тЖТ  const task = await surreal.select<TaskRow & { workspace: RecordId<"workspace", string> }>(taskRecord);
407тЖТ  if (!task) {
408тЖТ    throw new Error(`task not found: ${taskId}`);
409тЖТ  }
410тЖТ  if ((task.workspace.id as string) !== (workspaceRecord.id as string)) {
411тЖТ    throw new Error(`task not in workspace: ${taskId}`);
412тЖТ  }
413тЖТ
414тЖТ  // Resolve project from belongs_to edge
415тЖТ  const [projectEdges] = await surreal
416тЖТ    .query<[Array<{ out: RecordId<"project", string> }>]>(
417тЖТ      `SELECT out FROM belongs_to WHERE \`in\` = $task AND record::tb(out) = "project" LIMIT 1;`,
418тЖТ      { task: taskRecord },
419тЖТ    )
420тЖТ    .collect<[Array<{ out: RecordId<"project", string> }>]>();
421тЖТ
422тЖТ  let projectInfo: { id: string; name: string; status: string };
423тЖТ  let projectRecord: RecordId<"project", string> | undefined;
424тЖТ
425тЖТ  if (projectEdges.length > 0) {
426тЖТ    projectRecord = projectEdges[0].out;
427тЖТ    const project = await surreal.select<ProjectRow>(projectRecord);
428тЖТ    if (project) {
429тЖТ      projectInfo = { id: toRawId(project.id), name: project.name, status: project.status };
430тЖТ    } else {
431тЖТ      projectInfo = { id: toRawId(projectRecord), name: "unknown", status: "unknown" };
432тЖТ    }
433тЖТ  } else {
434тЖТ    projectInfo = { id: "unassigned", name: "unassigned", status: "unknown" };
435тЖТ  }
436тЖТ
437тЖТ  const taskScope = await buildTaskScope(surreal, workspaceRecord, taskId);
438тЖТ  const hotItems = await loadHotItems(surreal, workspaceRecord, projectRecord);
439тЖТ  const activeSessions = await loadActiveSessions(surreal, workspaceRecord, projectRecord, input.excludeSessionId);
440тЖТ
441тЖТ  return {
442тЖТ    workspace: { id: workspaceRecord.id as string, name: workspaceName },
443тЖТ    project: projectInfo,
444тЖТ    task_scope: taskScope,
445тЖТ    hot_items: hotItems,
446тЖТ    active_sessions: activeSessions,
447тЖТ  };
448тЖТ}
449тЖТ
450тЖТ// ===========================================================================
451тЖТ// Shared helpers
452тЖТ// ===========================================================================
453тЖТ
454тЖТ/** Load hot items: contested decisions, open observations, pending suggestions */
455тЖТasync function loadHotItems(
456тЖТ  surreal: Surreal,
457тЖТ  workspaceRecord: RecordId<"workspace", string>,
458тЖТ  projectRecord?: RecordId<"project", string>,
459тЖТ): Promise<HotItems> {
460тЖТ  // When project-scoped, filter decisions via belongs_to
461тЖТ  const decisionFilter = projectRecord
462тЖТ    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
463тЖТ    : "";
464тЖТ
465тЖТ  const hotQuery = `
466тЖТ    SELECT id, summary
467тЖТ    FROM decision
468тЖТ    WHERE workspace = $workspace AND status = "contested" ${decisionFilter}
469тЖТ    ORDER BY updated_at DESC LIMIT 10;
470тЖТ
471тЖТ    SELECT id, text, severity, category
472тЖТ    FROM observation
473тЖТ    WHERE workspace = $workspace AND status IN ["open", "acknowledged"] AND severity IN ["warning", "conflict"]
474тЖТ    ORDER BY created_at DESC LIMIT 10;
475тЖТ
476тЖТ    SELECT id, text, category, confidence
477тЖТ    FROM suggestion
478тЖТ    WHERE workspace = $workspace AND status = "pending"
479тЖТ    ORDER BY confidence DESC, created_at DESC LIMIT 5;
480тЖТ  `;
481тЖТ
482тЖТ  const [contestedDecisions, hotObservations, hotSuggestions] = await surreal
483тЖТ    .query<[ContestedDecisionRow[], HotObservationRow[], HotSuggestionRow[]]>(hotQuery, {
484тЖТ      workspace: workspaceRecord,
485тЖТ      ...(projectRecord ? { project: projectRecord } : {}),
486тЖТ    })
487тЖТ    .collect<[ContestedDecisionRow[], HotObservationRow[], HotSuggestionRow[]]>();
488тЖТ
489тЖТ  return {
490тЖТ    contested_decisions: contestedDecisions.map((d) => ({
491тЖТ      id: toRawId(d.id),
492тЖТ      summary: d.summary,
493тЖТ    })),
494тЖТ    open_observations: hotObservations.map((o) => ({
495тЖТ      id: toRawId(o.id),
496тЖТ      text: o.text,
497тЖТ      severity: o.severity,
498тЖТ      ...(o.category ? { category: o.category } : {}),
499тЖТ    })),
500тЖТ    pending_suggestions: hotSuggestions.map((s) => ({
501тЖТ      id: toRawId(s.id),
502тЖТ      text: s.text,
503тЖТ      category: s.category,
504тЖТ      confidence: s.confidence,
505тЖТ    })),
506тЖТ  };
507тЖТ}
508тЖТ
509тЖТ/** Build task-scoped context: subtasks, parent feature, siblings, dependencies, related sessions */
510тЖТasync function buildTaskScope(
511тЖТ  surreal: Surreal,
512тЖТ  workspaceRecord: RecordId<"workspace", string>,
513тЖТ  taskId: string,
514тЖТ): Promise<TaskScopeContext> {
515тЖТ  const taskRecord = new RecordId("task", taskId);
516тЖТ  const task = await surreal.select<TaskRow & { workspace: RecordId<"workspace", string> }>(taskRecord);
517тЖТ  if (!task) {
518тЖТ    throw new Error(`task not found: ${taskId}`);
519тЖТ  }
520тЖТ  if ((task.workspace.id as string) !== (workspaceRecord.id as string)) {
521тЖТ    throw new Error(`task not in workspace: ${taskId}`);
522тЖТ  }
523тЖТ
524тЖТ  const taskScopeQuery = `
525тЖТ    SELECT id, title, status
526тЖТ    FROM task
527тЖТ    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
528тЖТ    ORDER BY created_at ASC;
529тЖТ
530тЖТ    SELECT id, name, description
531тЖТ    FROM feature
532тЖТ    WHERE id IN (SELECT VALUE \`in\` FROM has_task WHERE out = $task)
533тЖТ    LIMIT 1;
534тЖТ
535тЖТ    SELECT id, title, status
536тЖТ    FROM task
537тЖТ    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
538тЖТ
539тЖТ    SELECT id, agent, ended_at, summary
540тЖТ    FROM agent_session
541тЖТ    WHERE task_id = $task AND ended_at != NONE
542тЖТ    ORDER BY ended_at DESC LIMIT 5;
543тЖТ  `;
544тЖТ
545тЖТ  const results = await surreal
546тЖТ    .query<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>(taskScopeQuery, {
547тЖТ      task: taskRecord,
548тЖТ    })
549тЖТ    .collect<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>();
550тЖТ
551тЖТ  const [subtaskRows, featureRows, dependencyRows, sessionRows] = results;
552тЖТ
553тЖТ  const parentFeature = featureRows.length > 0
554тЖТ    ? {
555тЖТ        id: toRawId(featureRows[0].id),
556тЖТ        name: featureRows[0].name,
557тЖТ        ...(featureRows[0].description ? { description: featureRows[0].description } : {}),
558тЖТ      }
559тЖТ    : undefined;
560тЖТ
561тЖТ  let siblingTasks: { id: string; title: string; status: string; source_session?: string }[] = [];
562тЖТ  if (parentFeature && featureRows.length > 0) {
563тЖТ    const [siblingRows] = await surreal
564тЖТ      .query<[TaskRow[]]>(
565тЖТ        `SELECT id, title, status, source_session FROM task
566тЖТ         WHERE id IN (SELECT VALUE out FROM has_task WHERE \`in\` = $feature)
567тЖТ           AND id != $task
568тЖТ         ORDER BY created_at ASC LIMIT 20;`,
569тЖТ        { feature: featureRows[0].id, task: taskRecord },
570тЖТ      )
571тЖТ      .collect<[TaskRow[]]>();
572тЖТ
573тЖТ    siblingTasks = siblingRows.map((t) => ({
574тЖТ      id: toRawId(t.id),
575тЖТ      title: t.title,
576тЖТ      status: t.status,
577тЖТ      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
578тЖТ    }));
579тЖТ  }
580тЖТ
581тЖТ  return {
582тЖТ    task: {
583тЖТ      id: toRawId(task.id),
584тЖТ      title: task.title,
585тЖТ      ...(task.description ? { description: task.description } : {}),
586тЖТ      status: task.status,
587тЖТ      ...(task.category ? { category: task.category } : {}),
588тЖТ    },
589тЖТ    subtasks: subtaskRows.map((s) => ({
590тЖТ      id: toRawId(s.id),
591тЖТ      title: s.title,
592тЖТ      status: s.status,
593тЖТ    })),
594тЖТ    parent_feature: parentFeature,
595тЖТ    sibling_tasks: siblingTasks,
596тЖТ    dependencies: dependencyRows.map((d) => ({
597тЖТ      id: toRawId(d.id),
598тЖТ      title: d.title,
599тЖТ      status: d.status,
600тЖТ    })),
601тЖТ    related_sessions: sessionRows.map((s) => ({
602тЖТ      id: toRawId(s.id),
603тЖТ      agent: s.agent,
604тЖТ      ended_at: toIso(s.ended_at),
605тЖТ      summary: s.summary ?? "",
606тЖТ    })),
607тЖТ  };
608тЖТ}
609тЖТ
610тЖТ/** Load active agent sessions, optionally scoped to a project */
611тЖТasync function loadActiveSessions(
612тЖТ  surreal: Surreal,
613тЖТ  workspaceRecord: RecordId<"workspace", string>,
614тЖТ  projectRecord?: RecordId<"project", string>,
615тЖТ  excludeSessionId?: string,
616тЖТ): Promise<ActiveSessionContext[]> {
617тЖТ  const excludeRecord = excludeSessionId
618тЖТ    ? new RecordId("agent_session", excludeSessionId)
619тЖТ    : new RecordId("agent_session", "__none__");
620тЖТ
621тЖТ  const projectFilter = projectRecord ? "AND project = $project" : "";
622тЖТ  const [sessionRows] = await surreal
623тЖТ    .query<[ActiveAgentSessionRow[]]>(
624тЖТ      `SELECT id, agent, started_at, task_id
625тЖТ       FROM agent_session
626тЖТ       WHERE workspace = $workspace ${projectFilter} AND ended_at = NONE AND id != $exclude
627тЖТ       ORDER BY started_at DESC LIMIT 10;`,
628тЖТ      { workspace: workspaceRecord, ...(projectRecord ? { project: projectRecord } : {}), exclude: excludeRecord },
629тЖТ    )
630тЖТ    .collect<[ActiveAgentSessionRow[]]>();
631тЖТ
632тЖТ  if (sessionRows.length === 0) return [];
633тЖТ
634тЖТ  const sessionIds = sessionRows.map((s) => s.id);
635тЖТ
636тЖТ  const [observationRows] = await surreal
637тЖТ    .query<[SessionObservationRow[]]>(
638тЖТ      `SELECT id, text, severity, source_session FROM observation
639тЖТ       WHERE source_session IN $sessions
640тЖТ         AND status IN ["open", "acknowledged"];`,
641тЖТ      { sessions: sessionIds },
642тЖТ    )
643тЖТ    .collect<[SessionObservationRow[]]>();
644тЖТ
645тЖТ  const taskIds = sessionRows
646тЖТ    .filter((s) => s.task_id)
647тЖТ    .map((s) => s.task_id!);
648тЖТ
649тЖТ  let taskTitles: Map<string, string> = new Map();
650тЖТ  if (taskIds.length > 0) {
651тЖТ    const [taskRows] = await surreal
652тЖТ      .query<[Array<{ id: RecordId<"task", string>; title: string }>]>(
653тЖТ        `SELECT id, title FROM task WHERE id IN $tasks;`,
654тЖТ        { tasks: taskIds },
655тЖТ      )
656тЖТ      .collect<[Array<{ id: RecordId<"task", string>; title: string }>]>();
657тЖТ    taskTitles = new Map(taskRows.map((t) => [toRawId(t.id), t.title]));
658тЖТ  }
659тЖТ
660тЖТ  const obsBySession = new Map<string, Array<{ id: string; text: string; severity: string }>>();
661тЖТ  for (const o of observationRows) {
662тЖТ    const sessionKey = toRawId(o.source_session);
663тЖТ    const arr = obsBySession.get(sessionKey) ?? [];
664тЖТ    arr.push({ id: toRawId(o.id), text: o.text, severity: o.severity });
665тЖТ    obsBySession.set(sessionKey, arr);
666тЖТ  }
667тЖТ
668тЖТ  const decisionsBySession = new Map<string, Array<{ id: string; summary: string }>>();
669тЖТ  for (const session of sessionRows) {
670тЖТ    const sessionKey = toRawId(session.id);
671тЖТ    const [decisionRows] = await surreal
672тЖТ      .query<[Array<{ id: RecordId<"decision", string>; summary: string }>]>(
673тЖТ        `SELECT id, summary FROM decision
674тЖТ         WHERE id IN (SELECT VALUE out FROM produced WHERE \`in\` = $session)
675тЖТ           AND status = "provisional";`,
676тЖТ        { session: session.id },
677тЖТ      )
678тЖТ      .collect<[Array<{ id: RecordId<"decision", string>; summary: string }>]>();
679тЖТ
680тЖТ    decisionsBySession.set(
681тЖТ      sessionKey,
682тЖТ      decisionRows.map((d) => ({ id: toRawId(d.id), summary: d.summary })),
683тЖТ    );
684тЖТ  }
685тЖТ
686тЖТ  return sessionRows.map((s) => {
687тЖТ    const sessionKey = toRawId(s.id);
688тЖТ    const taskId = s.task_id ? toRawId(s.task_id) : undefined;
689тЖТ    return {
690тЖТ      id: sessionKey,
691тЖТ      agent: s.agent,
692тЖТ      started_at: toIso(s.started_at),
693тЖТ      ...(taskId && taskTitles.has(taskId)
694тЖТ        ? { task: { id: taskId, title: taskTitles.get(taskId)! } }
695тЖТ        : {}),
696тЖТ      provisional_decisions: decisionsBySession.get(sessionKey) ?? [],
697тЖТ      observations: obsBySession.get(sessionKey) ?? [],
698тЖТ    };
699тЖТ  });
700тЖТ}
