702тЖТ/** Load entities changed since a timestamp (project-scoped) */
703тЖТasync function loadRecentChanges(
704тЖТ  surreal: Surreal,
705тЖТ  workspaceRecord: RecordId<"workspace", string>,
706тЖТ  projectRecord: RecordId<"project", string>,
707тЖТ  since: string,
708тЖТ): Promise<RecentChangeContext[]> {
709тЖТ  const sinceDate = new Date(since);
710тЖТ
711тЖТ  const query = `
712тЖТ    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
713тЖТ
714тЖТ    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
715тЖТ    FROM decision
716тЖТ    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
717тЖТ    ORDER BY updated_at DESC LIMIT 20;
718тЖТ
719тЖТ    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
720тЖТ    FROM task
721тЖТ    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
722тЖТ    ORDER BY updated_at DESC LIMIT 20;
723тЖТ
724тЖТ    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
725тЖТ    FROM question
726тЖТ    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
727тЖТ    ORDER BY updated_at DESC LIMIT 20;
728тЖТ
729тЖТ    LET $recent_observations = SELECT "observation" AS entity_type, text AS entity_name, severity AS change_type, updated_at AS changed_at
730тЖТ    FROM observation
731тЖТ    WHERE workspace = $workspace AND updated_at > $since
732тЖТ    ORDER BY updated_at DESC LIMIT 20;
733тЖТ
734тЖТ    LET $recent_suggestions = SELECT "suggestion" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
735тЖТ    FROM suggestion
736тЖТ    WHERE workspace = $workspace AND updated_at > $since
737тЖТ    ORDER BY updated_at DESC LIMIT 20;
738тЖТ
739тЖТ    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions, $recent_observations, $recent_suggestions]);
740тЖТ  `;
741тЖТ
742тЖТ  const results = await surreal
743тЖТ    .query<[null, null, null, null, null, null, RecentChangeRow[]]>(query, {
744тЖТ      project: projectRecord,
745тЖТ      workspace: workspaceRecord,
746тЖТ      since: sinceDate,
747тЖТ    })
748тЖТ    .collect<[null, null, null, null, null, null, RecentChangeRow[]]>();
749тЖТ
750тЖТ  const rows = results[6] ?? [];
751тЖТ
752тЖТ  return rows.map((r) => ({
753тЖТ    entity_type: r.entity_type,
754тЖТ    entity_name: r.entity_name,
755тЖТ    change_type: r.change_type,
756тЖТ    changed_at: toIso(r.changed_at),
757тЖТ  }));
758тЖТ}
