 1тЖТimport { z } from "zod";
 2тЖТimport { ENTITY_CATEGORIES, ENTITY_PRIORITIES } from "../../shared/contracts";
 3тЖТ
 4тЖТ// Azure structured output requires all properties in `required` тАФ no optional fields allowed.
 5тЖТ// Use "none" sentinel in the extraction schema, then strip it to undefined after parsing.
 6тЖТconst extractionCategorySchema = z.enum([...ENTITY_CATEGORIES, "none"]).transform(
 7тЖТ  (v) => (v === "none" ? undefined : v),
 8тЖТ);
 9тЖТ
10тЖТconst extractionPrioritySchema = z.enum([...ENTITY_PRIORITIES, "none"]).transform(
11тЖТ  (v) => (v === "none" ? undefined : v),
12тЖТ);
13тЖТ
14тЖТconst extractionEntityBaseSchema = z.object({
15тЖТ  tempId: z.string().min(1),
16тЖТ  kind: z.enum(["project", "feature", "task", "decision", "question"]),
17тЖТ  text: z.string().min(3).max(200),
18тЖТ  confidence: z.number().min(0).max(1),
19тЖТ  evidence: z.string().min(1),
20тЖТ  category: extractionCategorySchema,
21тЖТ  priority: extractionPrioritySchema,
22тЖТ}).strict();
23тЖТ
24тЖТconst extractionEntityWithAssigneeSchema = extractionEntityBaseSchema.extend({
25тЖТ  assignee_name: z.string().min(1),
26тЖТ}).strict();
27тЖТ
28тЖТconst extractionEntityWithResolvedFromSchema = extractionEntityBaseSchema.extend({
29тЖТ  resolvedFromMessageId: z.string().min(1),
30тЖТ}).strict();
31тЖТ
32тЖТconst extractionEntityWithAssigneeAndResolvedFromSchema = extractionEntityBaseSchema.extend({
33тЖТ  assignee_name: z.string().min(1),
34тЖТ  resolvedFromMessageId: z.string().min(1),
35тЖТ}).strict();
36тЖТ
37тЖТconst extractionEntitySchema = z.union([
38тЖТ  extractionEntityBaseSchema,
39тЖТ  extractionEntityWithAssigneeSchema,
40тЖТ  extractionEntityWithResolvedFromSchema,
41тЖТ  extractionEntityWithAssigneeAndResolvedFromSchema,
42тЖТ]);
43тЖТ
44тЖТexport const extractionRelationshipSchema = z.object({
45тЖТ  kind: z.string().min(1),
46тЖТ  fromTempId: z.string().min(1),
47тЖТ  toTempId: z.string().min(1),
48тЖТ  confidence: z.number().min(0).max(1),
49тЖТ  fromText: z.string().min(1),
50тЖТ  toText: z.string().min(1),
51тЖТ}).strict();
52тЖТ
53тЖТexport const extractionResultSchema = z.object({
54тЖТ  entities: z.array(extractionEntitySchema),
55тЖТ  relationships: z.array(extractionRelationshipSchema),
56тЖТ  tools: z.array(z.string().min(1)),
57тЖТ}).strict();
58тЖТ
59тЖТexport type ExtractionPromptEntity = z.infer<typeof extractionEntitySchema>;
60тЖТexport type ExtractionPromptRelationship = z.infer<typeof extractionRelationshipSchema>;
61тЖТexport type ExtractionPromptOutput = z.infer<typeof extractionResultSchema>;
62тЖТ
63тЖТexport function parseExtractionOutput(payload: unknown):
64тЖТ  | { ok: true; data: ExtractionPromptOutput }
65тЖТ  | { ok: false; error: string } {
66тЖТ  const result = extractionResultSchema.safeParse(payload);
67тЖТ  if (result.success) {
68тЖТ    return { ok: true, data: result.data };
69тЖТ  }
70тЖТ
71тЖТ  return {
72тЖТ    ok: false,
73тЖТ    error: result.error.issues[0]?.message ?? "Invalid extraction payload",
74тЖТ  };
75тЖТ}
