 1тЖТimport type { ReagraphNode, ReagraphEdge, GraphResponse, EntityKind } from "../../shared/contracts";
 2тЖТimport type { GraphViewRawResult } from "./queries";
 3тЖТ
 4тЖТ// Resolved hex values for OKLCH entity colors тАФ Three.js/WebGL cannot parse CSS variables.
 5тЖТexport function entityColor(kind: EntityKind): string {
 6тЖТ  switch (kind) {
 7тЖТ    case "project": return "#3b82f6";   // oklch(0.65 0.15 250)
 8тЖТ    case "feature": return "#14b8a6";   // oklch(0.65 0.15 170)
 9тЖТ    case "task": return "#22c55e";      // oklch(0.70 0.15 145)
10тЖТ    case "decision": return "#eab308";  // oklch(0.70 0.15 55)
11тЖТ    case "question": return "#a855f7";  // oklch(0.65 0.15 300)
12тЖТ    case "observation": return "#ef4444";
13тЖТ    case "suggestion": return "#06b6d4"; // cyan-500
14тЖТ    case "person": return "#f97316";    // oklch(0.65 0.15 25)
15тЖТ    case "workspace": return "#3b82f6";
16тЖТ    case "message": return "#22c55e";
17тЖТ  }
18тЖТ}
19тЖТ
20тЖТfunction titleCase(s: string): string {
21тЖТ  return s.split(" ").map((w) => w.charAt(0).toUpperCase() + w.slice(1)).join(" ");
22тЖТ}
23тЖТ
24тЖТexport function transformToReagraph(raw: GraphViewRawResult): GraphResponse {
25тЖТ  const connectionCounts = new Map<string, number>();
26тЖТ  for (const edge of raw.edges) {
27тЖТ    connectionCounts.set(edge.fromId, (connectionCounts.get(edge.fromId) ?? 0) + 1);
28тЖТ    connectionCounts.set(edge.toId, (connectionCounts.get(edge.toId) ?? 0) + 1);
29тЖТ  }
30тЖТ
31тЖТ  const nodes: ReagraphNode[] = raw.entities.map((entity) => {
32тЖТ    const kind = entity.kind as EntityKind;
33тЖТ    const kindBoost = kind === "project" ? 20
34тЖТ      : kind === "feature" ? 10
35тЖТ      : kind === "person" ? 8
36тЖТ      : 0;
37тЖТ    return {
38тЖТ      id: entity.id,
39тЖТ      label: entity.name.length > 32 ? entity.name.slice(0, 32) + "\u2026" : entity.name,
40тЖТ      fill: entityColor(kind),
41тЖТ      data: {
42тЖТ        kind,
43тЖТ        connectionCount: (connectionCounts.get(entity.id) ?? 0) + kindBoost,
44тЖТ        status: undefined,
45тЖТ      },
46тЖТ    };
47тЖТ  });
48тЖТ
49тЖТ  const edges: ReagraphEdge[] = raw.edges.map((edge) => ({
50тЖТ    id: edge.id,
51тЖТ    source: edge.fromId,
52тЖТ    target: edge.toId,
53тЖТ    label: titleCase(edge.kind.replace(/_/g, " ")),
54тЖТ    data: {
55тЖТ      type: edge.kind,
56тЖТ      confidence: edge.confidence,
57тЖТ    },
58тЖТ  }));
59тЖТ
60тЖТ  return { nodes, edges };
61тЖТ}
