102тЖТ  async function resolveWorkspaceById(workspaceId: string): Promise<{ workspaceRecord: RecordId<"workspace", string>; workspace: WorkspaceRow } | Response> {
103тЖТ    const workspaceRecord = new RecordId("workspace", workspaceId);
104тЖТ    const workspace = await surreal.select<WorkspaceRow>(workspaceRecord);
105тЖТ    if (!workspace) return jsonError("workspace not found", 404);
106тЖТ    return { workspaceRecord, workspace };
107тЖТ  }
108тЖТ
109тЖТ  async function requireScopedRecord(record: RecordId<string, string>, workspaceRecord: RecordId<"workspace", string>, label: string): Promise<Response | undefined> {
110тЖТ    if (record.table.name === "agent_session") {
111тЖТ      const session = await surreal.select<{ workspace: RecordId<"workspace", string> }>(record as RecordId<"agent_session", string>);
112тЖТ      if (!session) {
113тЖТ        return jsonError(`${label} not found`, 404);
114тЖТ      }
115тЖТ      if ((session.workspace.id as string) !== (workspaceRecord.id as string)) {
116тЖТ        return jsonError(`${label} is outside workspace scope`, 404);
117тЖТ      }
118тЖТ      return undefined;
119тЖТ    }
120тЖТ
121тЖТ    const scoped = await isEntityInWorkspace(surreal, workspaceRecord, record as RecordId<GraphEntityTable, string>);
122тЖТ    if (!scoped) {
123тЖТ      return jsonError(`${label} is outside workspace scope`, 404);
124тЖТ    }
125тЖТ    return undefined;
126тЖТ  }
