132тЖТ  /** POST /api/mcp/:workspaceId/auth/init тАФ Generate API key */
133тЖТ  async function handleAuthInit(workspaceId: string): Promise<Response> {
134тЖТ    const result = await resolveWorkspaceById(workspaceId);
135тЖТ    if (result instanceof Response) return result;
136тЖТ
137тЖТ    const apiKey = generateApiKey();
138тЖТ    const hash = await hashApiKey(apiKey);
139тЖТ
140тЖТ    await surreal.update(result.workspaceRecord).merge({ api_key_hash: hash, updated_at: new Date() });
141тЖТ
142тЖТ    logInfo("mcp.auth.init", "API key generated for workspace", { workspaceId });
143тЖТ
144тЖТ    return jsonResponse({ api_key: apiKey, workspace: { id: workspaceId, name: result.workspace.name } }, 200);
145тЖТ  }
