147тЖТ  /** GET /api/mcp/:workspaceId/projects тАФ List workspace projects */
148тЖТ  async function handleListProjects(workspaceId: string): Promise<Response> {
149тЖТ    const result = await resolveWorkspaceById(workspaceId);
150тЖТ    if (result instanceof Response) return result;
151тЖТ
152тЖТ    const [projectRows] = await surreal
153тЖТ      .query<[ProjectRow[]]>(
154тЖТ        "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
155тЖТ        { workspace: result.workspaceRecord },
156тЖТ      )
157тЖТ      .collect<[ProjectRow[]]>();
158тЖТ
159тЖТ    return jsonResponse({
160тЖТ      workspace: { id: workspaceId, name: result.workspace.name },
161тЖТ      projects: projectRows.map((p) => ({ id: p.id.id as string, name: p.name })),
162тЖТ    }, 200);
163тЖТ  }
