170тЖТ  async function handleWorkspaceContext(workspaceId: string, request: Request): Promise<Response> {
171тЖТ    const auth = await requireAuth(request, workspaceId);
172тЖТ    if (auth instanceof Response) return auth;
173тЖТ
174тЖТ    const body = await parseJsonBody<{ session_id?: string }>(request);
175тЖТ    if (body instanceof Response) return body;
176тЖТ
177тЖТ    try {
178тЖТ      const overview = await buildWorkspaceOverview({
179тЖТ        surreal,
180тЖТ        workspaceRecord: auth.workspaceRecord,
181тЖТ        workspaceName: auth.workspaceName,
182тЖТ        ...(body.session_id ? { excludeSessionId: requireRawId(body.session_id, "session_id") } : {}),
183тЖТ      });
184тЖТ      logInfo("mcp.workspace-context.built", "Workspace overview assembled", { workspaceId, projectCount: overview.projects.length });
185тЖТ      return jsonResponse(overview, 200);
186тЖТ    } catch (error) {
187тЖТ      logError("mcp.workspace-context.failed", "Failed to build workspace overview", error);
188тЖТ      return jsonError("failed to build workspace overview", 500);
189тЖТ    }
190тЖТ  }
