192тЖТ  /** POST /api/mcp/:workspaceId/project-context тАФ Full project context (project_id required) */
193тЖТ  async function handleProjectContext(workspaceId: string, request: Request): Promise<Response> {
194тЖТ    const auth = await requireAuth(request, workspaceId);
195тЖТ    if (auth instanceof Response) return auth;
196тЖТ
197тЖТ    const body = await parseJsonBody<{ project_id: string; task_id?: string; since?: string; session_id?: string }>(request);
198тЖТ    if (body instanceof Response) return body;
199тЖТ    if (!body.project_id) return jsonError("project_id is required", 400);
200тЖТ
201тЖТ    let projectId: string;
202тЖТ    let taskId: string | undefined;
203тЖТ    let sessionId: string | undefined;
204тЖТ    try {
205тЖТ      projectId = requireRawId(body.project_id, "project_id");
206тЖТ      taskId = body.task_id ? requireRawId(body.task_id, "task_id") : undefined;
207тЖТ      sessionId = body.session_id ? requireRawId(body.session_id, "session_id") : undefined;
208тЖТ    } catch (error) {
209тЖТ      return jsonError(error instanceof Error ? error.message : "invalid id format", 400);
210тЖТ    }
211тЖТ
212тЖТ    const projectRecord = new RecordId("project", projectId);
213тЖТ    const scopedProjectError = await requireScopedRecord(projectRecord, auth.workspaceRecord, "project");
214тЖТ    if (scopedProjectError) return scopedProjectError;
215тЖТ    if (taskId) {
216тЖТ      const scopedTaskError = await requireScopedRecord(new RecordId("task", taskId), auth.workspaceRecord, "task");
217тЖТ      if (scopedTaskError) return scopedTaskError;
218тЖТ    }
219тЖТ
220тЖТ    try {
221тЖТ      const contextPacket = await buildProjectContext({
222тЖТ        surreal,
223тЖТ        workspaceRecord: auth.workspaceRecord,
224тЖТ        workspaceName: auth.workspaceName,
225тЖТ        projectRecord,
226тЖТ        ...(taskId ? { taskId } : {}),
227тЖТ        since: body.since,
228тЖТ        ...(sessionId ? { excludeSessionId: sessionId } : {}),
229тЖТ      });
230тЖТ
231тЖТ      logInfo("mcp.project-context.built", "Project context assembled", {
232тЖТ        workspaceId,
233тЖТ        projectId,
234тЖТ        taskId,
235тЖТ        decisionsCount:
236тЖТ          contextPacket.decisions.confirmed.length +
237тЖТ          contextPacket.decisions.provisional.length +
238тЖТ          contextPacket.decisions.contested.length,
239тЖТ        tasksCount: contextPacket.active_tasks.length,
