430тЖТ    const auth = await requireAuth(request, workspaceId);
431тЖТ    if (auth instanceof Response) return auth;
432тЖТ
433тЖТ    const body = await parseJsonBody<{
434тЖТ      question: string;
435тЖТ      options?: string[];
436тЖТ      context?: { project?: string; feature?: string };
437тЖТ    }>(request);
438тЖТ    if (body instanceof Response) return body;
439тЖТ    if (!body.question) return jsonError("question is required", 400);
440тЖТ
441тЖТ    // Embed the question and search for related decisions
442тЖТ    const queryEmbedding = await createEmbeddingVector(
443тЖТ      deps.embeddingModel,
444тЖТ      body.question,
445тЖТ      config.embeddingDimension,
446тЖТ    );
447тЖТ
448тЖТ    if (!queryEmbedding) {
449тЖТ      return jsonResponse({
450тЖТ        decision: undefined,
451тЖТ        confidence: 0,
452тЖТ        status: "unresolved",
453тЖТ        rationale: "Could not create embedding for question",
454тЖТ        sources: [],
455тЖТ      }, 200);
456тЖТ    }
457тЖТ
458тЖТ    const projectRecord = body.context?.project
459тЖТ      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
460тЖТ      : undefined;
461тЖТ
462тЖТ    const candidates = await searchEntitiesByEmbedding({
463тЖТ      surreal,
464тЖТ      workspaceRecord: auth.workspaceRecord,
465тЖТ      queryEmbedding,
466тЖТ      kinds: ["decision"],
467тЖТ      ...(projectRecord ? { projectRecord } : {}),
468тЖТ      limit: 10,
469тЖТ    });
470тЖТ
471тЖТ    // Check if any existing decision resolves the question
472тЖТ    const questionTokens = normalizeTokens(body.question);
473тЖТ    const relevant = candidates.filter((c) => {
474тЖТ      const tokens = normalizeTokens(c.name);
475тЖТ      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
476тЖТ    });
477тЖТ
478тЖТ    if (relevant.length > 0) {
479тЖТ      const best = relevant[0];
480тЖТ      return jsonResponse({
481тЖТ        decision: best.name,
482тЖТ        confidence: Number(best.score.toFixed(4)),
483тЖТ        status: best.status ?? "unknown",
484тЖТ        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
485тЖТ        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
486тЖТ      }, 200);
487тЖТ    }
488тЖТ
489тЖТ    return jsonResponse({
490тЖТ      decision: undefined,
491тЖТ      confidence: 0,
492тЖТ      status: "unresolved",
493тЖТ      rationale: "No existing decision found that resolves this question",
494тЖТ      sources: candidates.slice(0, 5).map((c) => ({
495тЖТ        id: `${c.kind}:${c.id}`,
496тЖТ        name: c.name,
497тЖТ        score: Number(c.score.toFixed(4)),
498тЖТ      })),
499тЖТ    }, 200);

