 77тЖТ    77тЖТ    77тЖТ      .map((t) => t.trim())
 78тЖТ    78тЖТ    78тЖТ      .filter((t) => t.length > 2),
 79тЖТ    79тЖТ    79тЖТ  );
 80тЖТ    80тЖТ    80тЖТ}
