502тЖТ  /** POST /api/mcp/:workspaceId/constraints/check тАФ Check proposed action */
503тЖТ  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
504тЖТ    const auth = await requireAuth(request, workspaceId);
505тЖТ    if (auth instanceof Response) return auth;
506тЖТ
507тЖТ    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
508тЖТ    if (body instanceof Response) return body;
509тЖТ    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
510тЖТ
511тЖТ    const queryEmbedding = await createEmbeddingVector(
512тЖТ      deps.embeddingModel,
513тЖТ      body.proposed_action,
514тЖТ      config.embeddingDimension,
515тЖТ    );
516тЖТ
517тЖТ    if (!queryEmbedding) {
518тЖТ      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
519тЖТ    }
520тЖТ
521тЖТ    const projectRecord = body.project
522тЖТ      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
523тЖТ      : undefined;
524тЖТ
525тЖТ    const candidates = await listDecisionConstraintCandidates({
526тЖТ      surreal,
527тЖТ      workspaceRecord: auth.workspaceRecord,
528тЖТ      queryEmbedding,
529тЖТ      ...(projectRecord ? { projectRecord } : {}),
530тЖТ      limit: 14,
531тЖТ    });
532тЖТ
533тЖТ    const actionTokens = normalizeTokens(body.proposed_action);
534тЖТ    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
535тЖТ    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
536тЖТ    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
537тЖТ
538тЖТ    for (const candidate of candidates) {
539тЖТ      const candidateTokens = normalizeTokens(candidate.name);
540тЖТ      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
541тЖТ      const status = candidate.status?.toLowerCase();
542тЖТ
543тЖТ      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
544тЖТ        hardConflicts.push({
545тЖТ          id: `${candidate.kind}:${candidate.id}`,
546тЖТ          name: candidate.name,
547тЖТ          score: Number(candidate.score.toFixed(4)),
548тЖТ          reason: `Decision is marked ${status}.`,
549тЖТ        });
550тЖТ        continue;
551тЖТ      }
552тЖТ
553тЖТ      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
554тЖТ        supporting.push({
555тЖТ          id: `${candidate.kind}:${candidate.id}`,
556тЖТ          name: candidate.name,
557тЖТ          score: Number(candidate.score.toFixed(4)),
558тЖТ          reason: "High-similarity decision aligns with proposed action.",
559тЖТ        });
560тЖТ        continue;
561тЖТ      }
562тЖТ
563тЖТ      if (candidate.score >= 0.72) {
564тЖТ        softTensions.push({
565тЖТ          id: `${candidate.kind}:${candidate.id}`,
566тЖТ          name: candidate.name,
567тЖТ          score: Number(candidate.score.toFixed(4)),
568тЖТ          reason: overlap
569тЖТ            ? "Related decision/question may require consistency checks."
570тЖТ            : "Semantically related context may be affected.",
571тЖТ        });
572тЖТ      }
573тЖТ    }
574тЖТ
575тЖТ    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
576тЖТ  }
