1052тЖТexport async function getProjectStatus(input: {
1053тЖТ  surreal: Surreal;
1054тЖТ  workspaceRecord: RecordId<"workspace", string>;
1055тЖТ  projectInput: string;
1056тЖТ}): Promise<ProjectStatus> {
1057тЖТ  const projectRecord = await resolveWorkspaceProjectRecord({
1058тЖТ    surreal: input.surreal,
1059тЖТ    workspaceRecord: input.workspaceRecord,
1060тЖТ    projectInput: input.projectInput,
1061тЖТ  });
1062тЖТ
1063тЖТ  const project = await input.surreal.select<{ id: RecordId<"project", string>; name: string }>(projectRecord);
1064тЖТ  if (!project) {
1065тЖТ    throw new Error(`project not found: ${toRecordIdString(projectRecord)}`);
1066тЖТ  }
1067тЖТ
1068тЖТ  const [featureRows] = await input.surreal
1069тЖТ    .query<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>(
1070тЖТ      "SELECT id, name, status FROM feature WHERE id IN (SELECT VALUE out FROM has_feature WHERE `in` = $project);",
1071тЖТ      { project: projectRecord },
1072тЖТ    )
1073тЖТ    .collect<[Array<{ id: RecordId<"feature", string>; name: string; status: string }>]>();
1074тЖТ
1075тЖТ  const [taskRows] = await input.surreal
1076тЖТ    .query<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>(
1077тЖТ      [
1078тЖТ        "SELECT id, title, status, priority, created_at",
1079тЖТ        "FROM task",
1080тЖТ        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1081тЖТ        "OR id IN (",
1082тЖТ        "  SELECT VALUE out",
1083тЖТ        "  FROM has_task",
1084тЖТ        "  WHERE `in` IN (SELECT VALUE out FROM has_feature WHERE `in` = $project)",
1085тЖТ        ")",
1086тЖТ        "ORDER BY created_at DESC",
1087тЖТ        "LIMIT 100;",
1088тЖТ      ].join(" "),
1089тЖТ      { project: projectRecord },
1090тЖТ    )
1091тЖТ    .collect<[Array<{ id: RecordId<"task", string>; title: string; status: string; priority?: string; created_at: string | Date }>]>();
1092тЖТ
1093тЖТ  const [decisionRows] = await input.surreal
1094тЖТ    .query<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>(
1095тЖТ      [
1096тЖТ        "SELECT id, summary, status, priority, created_at",
1097тЖТ        "FROM decision",
1098тЖТ        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1099тЖТ        "ORDER BY created_at DESC",
1100тЖТ        "LIMIT 30;",
1101тЖТ      ].join(" "),
1102тЖТ      { project: projectRecord },
1103тЖТ    )
1104тЖТ    .collect<[Array<{ id: RecordId<"decision", string>; summary: string; status: string; priority?: string; created_at: string | Date }>]>();
1105тЖТ
1106тЖТ  const [questionRows] = await input.surreal
1107тЖТ    .query<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>(
1108тЖТ      [
1109тЖТ        "SELECT id, text, status, priority, created_at",
1110тЖТ        "FROM question",
1111тЖТ        "WHERE id IN (SELECT VALUE `in` FROM belongs_to WHERE out = $project)",
1112тЖТ        "ORDER BY created_at DESC",
1113тЖТ        "LIMIT 30;",
1114тЖТ      ].join(" "),
1115тЖТ      { project: projectRecord },
1116тЖТ    )
1117тЖТ    .collect<[Array<{ id: RecordId<"question", string>; text: string; status: string; priority?: string; created_at: string | Date }>]>();
1118тЖТ
1119тЖТ  let active = 0;
1120тЖТ  let completed = 0;
1121тЖТ  let blocked = 0;
1122тЖТ
1123тЖТ  for (const task of taskRows) {
1124тЖТ    const normalized = task.status.trim().toLowerCase();
1125тЖТ    if (normalized === "blocked") {
1126тЖТ      blocked += 1;
1127тЖТ      continue;
1128тЖТ    }
1129тЖТ
1130тЖТ    if (normalized === "done" || normalized === "completed") {
1131тЖТ      completed += 1;
1132тЖТ      continue;
1133тЖТ    }
1134тЖТ
1135тЖТ    active += 1;
1136тЖТ  }
1137тЖТ
1138тЖТ  return {
1139тЖТ    project: {
1140тЖТ      id: toRecordIdString(project.id),
1141тЖТ      name: project.name,
1142тЖТ    },
1143тЖТ    tasks: {
1144тЖТ      active,
1145тЖТ      completed,
1146тЖТ      blocked,
1147тЖТ      recent: taskRows.slice(0, 20).map((task) => ({
1148тЖТ        id: toRecordIdString(task.id),
1149тЖТ        name: task.title,
1150тЖТ        status: task.status,
1151тЖТ        ...(task.priority ? { priority: task.priority } : {}),
1152тЖТ      })),
1153тЖТ    },
1154тЖТ    decisions: decisionRows.map((decision) => ({
1155тЖТ      id: toRecordIdString(decision.id),
1156тЖТ      name: decision.summary,
1157тЖТ      status: decision.status,
1158тЖТ      ...(decision.priority ? { priority: decision.priority } : {}),
1159тЖТ    })),
1160тЖТ    questions: questionRows.map((question) => ({
1161тЖТ      id: toRecordIdString(question.id),
1162тЖТ      name: question.text,
1163тЖТ      status: question.status,
1164тЖТ      ...(question.priority ? { priority: question.priority } : {}),
1165тЖТ    })),
1166тЖТ    features: featureRows.map((feature) => ({
1167тЖТ      id: toRecordIdString(feature.id),
1168тЖТ      name: feature.name,
1169тЖТ      status: feature.status,
1170тЖТ    })),
1171тЖТ  };

