150тЖТexport function parseRecordIdString<T extends string>(
151тЖТ  value: string,
152тЖТ  allowedTables: T[],
153тЖТ  fallbackTable?: T,
154тЖТ): RecordId<T, string> {
155тЖТ  const normalized = value.trim();
156тЖТ  if (normalized.length === 0) {
157тЖТ    throw new Error("record id is required");
158тЖТ  }
159тЖТ
160тЖТ  const separatorIndex = normalized.indexOf(":");
161тЖТ  if (separatorIndex === -1) {
162тЖТ    if (!fallbackTable) {
163тЖТ      throw new Error(`record id must be prefixed with one of: ${allowedTables.join(", ")}`);
164тЖТ    }
165тЖТ
166тЖТ    return new RecordId(fallbackTable, normalized) as RecordId<T, string>;
167тЖТ  }
168тЖТ
169тЖТ  const table = normalized.slice(0, separatorIndex) as T;
170тЖТ  const id = normalized.slice(separatorIndex + 1);
171тЖТ  if (!allowedTables.includes(table)) {
172тЖТ    throw new Error(`record id table must be one of: ${allowedTables.join(", ")}`);
173тЖТ  }
174тЖТ
175тЖТ  if (id.length === 0) {
176тЖТ    throw new Error("record id is missing its identifier component");
177тЖТ  }
178тЖТ
179тЖТ  return new RecordId(table, id) as RecordId<T, string>;
180тЖТ}
