  1тЖТimport { existsSync, mkdirSync, chmodSync, unlinkSync } from "node:fs";
  2тЖТimport { join } from "node:path";
  3тЖТimport { findGitRoot, saveRepoConfig, loadGlobalConfig } from "../config";
  4тЖТimport { BrainHttpClient } from "../http-client";
  5тЖТimport { BRAIN_HOOKS, BRAIN_CLAUDE_MD, BRAIN_COMMANDS } from "./init-content";
  6тЖТ
  7тЖТconst DEFAULT_SERVER_URL = "http://localhost:3000";
  8тЖТ
  9тЖТexport async function runInit(): Promise<void> {
 10тЖТ  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;
 11тЖТ  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
 12тЖТ
 13тЖТ  const gitRoot = findGitRoot(process.cwd());
 14тЖТ  if (!gitRoot) {
 15тЖТ    console.error("Not inside a git repository. Run brain init from a project directory.");
 16тЖТ    process.exit(1);
 17тЖТ  }
 18тЖТ
 19тЖТ  if (!workspaceId) {
 20тЖТ    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
 21тЖТ    console.error("Find it in the Brain web UI or the database.");
 22тЖТ    process.exit(1);
 23тЖТ  }
 24тЖТ
 25тЖТ  console.log("Brain Init\nтФАтФАтФАтФАтФАтФАтФАтФАтФАтФА\n");
 26тЖТ
 27тЖТ  // Step 1: Auth
 28тЖТ  await setupAuth(serverUrl, workspaceId, gitRoot);
 29тЖТ
 30тЖТ  // Step 2: .mcp.json
 31тЖТ  await setupMcpJson(gitRoot);
 32тЖТ
 33тЖТ  // Step 3: .claude/settings.json hooks
 34тЖТ  await setupClaudeHooks(gitRoot);
 35тЖТ
 36тЖТ  // Step 4: CLAUDE.md
 37тЖТ  await setupClaudeMd(gitRoot);
 38тЖТ
 39тЖТ  // Step 5: Commands
 40тЖТ  await setupCommands(gitRoot);
 41тЖТ
 42тЖТ  // Step 6: Git hooks
 43тЖТ  installGitHooks(gitRoot);
 44тЖТ
 45тЖТ  console.log(`\nDone. Restart Claude Code to activate.`);
 46тЖТ}
 47тЖТ
 48тЖТ// ---------------------------------------------------------------------------
 49тЖТ// Step 1: Auth
 50тЖТ// ---------------------------------------------------------------------------
 51тЖТ
 52тЖТasync function setupAuth(serverUrl: string, workspaceId: string, gitRoot: string): Promise<void> {
 53тЖТ  const global = await loadGlobalConfig();
 54тЖТ  const existing = global?.repos[gitRoot];
 55тЖТ  if (existing && existing.workspace === workspaceId) {
 56тЖТ    console.log(`тЬУ Auth: already configured for ${gitRoot}`);
 57тЖТ    return;
 58тЖТ  }
 59тЖТ
 60тЖТ  const initResult = await BrainHttpClient.initApiKey(serverUrl, workspaceId);
 61тЖТ  await saveRepoConfig(serverUrl, gitRoot, {
 62тЖТ    workspace: workspaceId,
 63тЖТ    api_key: initResult.api_key,
 64тЖТ  });
 65тЖТ  console.log(`тЬУ Auth: API key saved for ${gitRoot} тЖТ workspace "${initResult.workspace.name}"`);
 66тЖТ}
 67тЖТ
 68тЖТ// ---------------------------------------------------------------------------
 69тЖТ// Step 2: .mcp.json
 70тЖТ// ---------------------------------------------------------------------------
 71тЖТ
 72тЖТasync function setupMcpJson(gitRoot: string): Promise<void> {
 73тЖТ  const mcpPath = join(gitRoot, ".mcp.json");
 74тЖТ  const file = Bun.file(mcpPath);
 75тЖТ  let mcp: { mcpServers: Record<string, unknown> } = { mcpServers: {} };
 76тЖТ
 77тЖТ  if (await file.exists()) {
 78тЖТ    try {
 79тЖТ      mcp = await file.json();
 80тЖТ      mcp.mcpServers ??= {};
 81тЖТ    } catch {
 82тЖТ      // Corrupted file тАФ overwrite
 83тЖТ    }
 84тЖТ  }
 85тЖТ
 86тЖТ  mcp.mcpServers.brain = { command: "brain", args: ["mcp"] };
 87тЖТ  await Bun.write(mcpPath, JSON.stringify(mcp, null, 2) + "\n");
 88тЖТ  console.log("тЬУ MCP: .mcp.json updated");
 89тЖТ}
 90тЖТ
 91тЖТ// ---------------------------------------------------------------------------
 92тЖТ// Step 3: .claude/settings.json hooks
 93тЖТ// ---------------------------------------------------------------------------
 94тЖТ
 95тЖТtype HookEntry = { type: string; command?: string; prompt?: string };
 96тЖТtype SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
 97тЖТ
 98тЖТasync function setupClaudeHooks(gitRoot: string): Promise<void> {
 99тЖТ  const claudeDir = join(gitRoot, ".claude");
100тЖТ  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
101тЖТ
102тЖТ  const settingsPath = join(claudeDir, "settings.json");
103тЖТ  const file = Bun.file(settingsPath);
104тЖТ  let settings: Record<string, unknown> = {};
105тЖТ
106тЖТ  if (await file.exists()) {
107тЖТ    try {
108тЖТ      settings = await file.json();
109тЖТ    } catch {
110тЖТ      // Corrupted тАФ start fresh
111тЖТ    }
112тЖТ  }
113тЖТ
114тЖТ  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
115тЖТ  let added = 0;
116тЖТ
117тЖТ  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
118тЖТ    hooks[event] ??= [];
119тЖТ
120тЖТ    const hasBrain = hooks[event].some((group) =>
121тЖТ      group.hooks?.some(
122тЖТ        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
123тЖТ      ),
124тЖТ    );
125тЖТ
126тЖТ    if (!hasBrain) {
127тЖТ      hooks[event].push({ hooks: hookDefs as HookEntry[] });
128тЖТ      added++;
129тЖТ    }
130тЖТ  }
131тЖТ
132тЖТ  settings.hooks = hooks;
133тЖТ  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
134тЖТ  console.log(`тЬУ Hooks: .claude/settings.json updated (${added} hooks added)`);
135тЖТ}
136тЖТ
137тЖТ// ---------------------------------------------------------------------------
138тЖТ// Step 4: CLAUDE.md
139тЖТ// ---------------------------------------------------------------------------
140тЖТ
141тЖТconst MARKER_START = "<!-- brain-plugin-start -->";
142тЖТconst MARKER_END = "<!-- brain-plugin-end -->";
143тЖТ
144тЖТasync function setupClaudeMd(gitRoot: string): Promise<void> {
145тЖТ  const claudeMdPath = join(gitRoot, "CLAUDE.md");
146тЖТ  const file = Bun.file(claudeMdPath);
147тЖТ  let content = "";
148тЖТ
149тЖТ  if (await file.exists()) {
150тЖТ    content = await file.text();
151тЖТ  }
152тЖТ
153тЖТ  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
154тЖТ
155тЖТ  const startIdx = content.indexOf(MARKER_START);
156тЖТ  const endIdx = content.indexOf(MARKER_END);
157тЖТ
158тЖТ  if (startIdx !== -1 && endIdx !== -1) {
159тЖТ    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
160тЖТ  } else {
161тЖТ    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
162тЖТ    content = content + separator + brainBlock + "\n";
163тЖТ  }
164тЖТ
165тЖТ  await Bun.write(claudeMdPath, content);
166тЖТ  console.log("тЬУ CLAUDE.md: Brain plugin instructions added");
167тЖТ}
168тЖТ
169тЖТ// ---------------------------------------------------------------------------
170тЖТ// Step 6: Git hooks
171тЖТ// ---------------------------------------------------------------------------
172тЖТ
173тЖТexport function installGitHooks(gitRoot?: string): void {
174тЖТ  const root = gitRoot ?? findGitRoot(process.cwd());
175тЖТ  if (!root) {
176тЖТ    console.log("  No .git directory found тАФ skipping git hook installation.");
177тЖТ    return;
178тЖТ  }
179тЖТ
180тЖТ  const hooksDir = join(root, ".git", "hooks");
181тЖТ  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
182тЖТ
183тЖТ  const preCommitPath = join(hooksDir, "pre-commit");
184тЖТ  const postCommitPath = join(hooksDir, "post-commit");
185тЖТ  const preCommitScript = `#!/bin/sh
186тЖТ# Brain pre-commit hook: check for task completion and unlogged decisions
187тЖТbrain check-commit
188тЖТ`;
189тЖТ
190тЖТ  if (!existsSync(preCommitPath)) {
191тЖТ    Bun.writeSync(Bun.openSync(preCommitPath, "w"), preCommitScript);
192тЖТ    chmodSync(preCommitPath, 0o755);
193тЖТ    console.log("тЬУ Git: pre-commit hook installed");
194тЖТ  } else {
195тЖТ    console.log("тЬУ Git: pre-commit hook already exists");
196тЖТ  }
197тЖТ
198тЖТ  // Remove legacy Brain post-commit hook
199тЖТ  if (existsSync(postCommitPath)) {
200тЖТ    const postCommitContent = Bun.file(postCommitPath).textSync();
201тЖТ    const isBrainManaged =
202тЖТ      postCommitContent.includes("Brain post-commit hook") &&
203тЖТ      postCommitContent.includes("brain log-commit");
204тЖТ    if (isBrainManaged) {
205тЖТ      unlinkSync(postCommitPath);
206тЖТ      console.log("  Removed legacy Brain post-commit hook");
207тЖТ    }
208тЖТ  }
209тЖТ}
210тЖТ
211тЖТasync function setupCommands(gitRoot: string): Promise<void> {
212тЖТ  const commandsDir = join(gitRoot, ".claude", "commands");
213тЖТ  if (!existsSync(commandsDir)) mkdirSync(commandsDir, { recursive: true });
214тЖТ
215тЖТ  let count = 0;
216тЖТ  for (const [filename, content] of Object.entries(BRAIN_COMMANDS)) {
217тЖТ    await Bun.write(join(commandsDir, filename), content + "\n");
218тЖТ    count++;
219тЖТ  }
220тЖТ
221тЖТ  console.log(`тЬУ Commands: ${count} slash commands installed to .claude/commands/`);
222тЖТ}
