 1тЖТimport { HttpError } from "../http/errors";
 2тЖТimport { logError, logInfo } from "../http/observability";
 3тЖТimport { jsonError, jsonResponse } from "../http/response";
 4тЖТimport type { ServerDependencies } from "../runtime/types";
 5тЖТimport { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 6тЖТimport {
 7тЖТ  getEntityDetail,
 8тЖТ  parseRecordIdString,
 9тЖТ  type GraphEntityTable,
10тЖТ} from "../graph/queries";
11тЖТimport type { EntityDetailResponse } from "../../shared/contracts";
12тЖТ
13тЖТexport function createEntityDetailHandler(
14тЖТ  deps: ServerDependencies,
15тЖТ): (entityId: string, url: URL) => Promise<Response> {
16тЖТ  return (entityId: string, url: URL) => handleEntityDetail(deps, entityId, url);
17тЖТ}
18тЖТ
19тЖТasync function handleEntityDetail(
20тЖТ  deps: ServerDependencies,
21тЖТ  entityId: string,
22тЖТ  url: URL,
23тЖТ): Promise<Response> {
24тЖТ  const workspaceId = url.searchParams.get("workspaceId")?.trim();
25тЖТ  if (!workspaceId) {
26тЖТ    return jsonError("workspaceId is required", 400);
27тЖТ  }
28тЖТ
29тЖТ  let workspaceRecord;
30тЖТ  try {
31тЖТ    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
32тЖТ  } catch (error) {
33тЖТ    if (error instanceof HttpError) {
34тЖТ      return jsonError(error.message, error.status);
35тЖТ    }
36тЖТ    logError("entity.detail.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
37тЖТ    return jsonError("failed to resolve workspace", 500);
38тЖТ  }
39тЖТ
40тЖТ  try {
41тЖТ    const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "suggestion"];
42тЖТ    const entityRecord = parseRecordIdString(entityId, entityTables);
43тЖТ    const detail = await getEntityDetail({
44тЖТ      surreal: deps.surreal,
45тЖТ      workspaceRecord,
46тЖТ      entityRecord,
47тЖТ    });
48тЖТ
49тЖТ    const response: EntityDetailResponse = {
50тЖТ      entity: detail.entity,
51тЖТ      relationships: detail.relationships,
52тЖТ      provenance: detail.provenance,
53тЖТ    };
54тЖТ
55тЖТ    logInfo("entity.detail.served", "Entity detail served", {
56тЖТ      workspaceId,
57тЖТ      entityId,
58тЖТ      relationshipCount: detail.relationships.length,
59тЖТ      provenanceCount: detail.provenance.length,
60тЖТ    });
61тЖТ
62тЖТ    return jsonResponse(response, 200);
63тЖТ  } catch (error) {
64тЖТ    logError("entity.detail.failed", "Entity detail failed", error, {
65тЖТ      workspaceId,
66тЖТ      entityId,
67тЖТ    });
68тЖТ    const message = error instanceof Error ? error.message : "entity detail failed";
69тЖТ    return jsonError(message, 500);
70тЖТ  }
71тЖТ}
