 946тЖТ  const table = input.entityRecord.table.name as GraphEntityTable;
 947тЖТ  const row = await input.surreal.select<Record<string, unknown>>(input.entityRecord);
 948тЖТ  if (!row) {
 949тЖТ    throw new Error(`entity not found: ${table}:${toRecordIdString(input.entityRecord)}`);
 950тЖТ  }
 951тЖТ
 952тЖТ  const name = await readEntityName(input.surreal, input.entityRecord);
