 961тЖТ    limit: 40,
 962тЖТ  });
 963тЖТ
 964тЖТ  const [provenanceRows] = await input.surreal
 965тЖТ    .query<[
 966тЖТ      Array<{
 967тЖТ        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
 968тЖТ        confidence: number;
 969тЖТ        extracted_at: string | Date;
 970тЖТ        evidence?: string;
 971тЖТ        evidence_source?: RecordId<"message", string>;
 972тЖТ        resolved_from?: RecordId<"message", string>;
 973тЖТ        from_text?: string;
 974тЖТ      }>,
 975тЖТ    ]>(
 976тЖТ      [
 977тЖТ        "SELECT `in`, confidence, extracted_at, evidence, evidence_source, resolved_from, from_text",
 978тЖТ        "FROM extraction_relation",
 979тЖТ        "WHERE out = $entity",
 980тЖТ        "AND (",
 981тЖТ        "  `in` IN (",
 982тЖТ        "    SELECT VALUE id",
 983тЖТ        "    FROM message",
 984тЖТ        "    WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
 985тЖТ        "  )",
 986тЖТ        "  OR `in` IN (SELECT VALUE id FROM document_chunk WHERE workspace = $workspace)",
 987тЖТ        "  OR `in` IN (SELECT VALUE id FROM git_commit WHERE workspace = $workspace)",
 988тЖТ        ")",
 989тЖТ        "ORDER BY extracted_at DESC",
 990тЖТ        "LIMIT 40;",
 991тЖТ      ].join(" "),
 992тЖТ      {
 993тЖТ        workspace: input.workspaceRecord,
 994тЖТ        entity: input.entityRecord,
 995тЖТ      },
 996тЖТ    )
 997тЖТ    .collect<[
 998тЖТ      Array<{
 999тЖТ        in: RecordId<"message" | "document_chunk" | "git_commit", string>;
1000тЖТ        confidence: number;
1001тЖТ        extracted_at: string | Date;
1002тЖТ        evidence?: string;
1003тЖТ        evidence_source?: RecordId<"message", string>;
1004тЖТ        resolved_from?: RecordId<"message", string>;
1005тЖТ        from_text?: string;
1006тЖТ      }>,
1007тЖТ    ]>();
1008тЖТ
1009тЖТ  // Resolve conversationIds for message-type provenance sources
1010тЖТ  const messageProvenanceRows = provenanceRows.filter((r) => r.in.table.name === "message");
1011тЖТ  let convMap: Map<string, string> | undefined;
1012тЖТ  if (messageProvenanceRows.length > 0) {
1013тЖТ    const [convRows] = await input.surreal
