1024тЖТ    sourceKind: row.in.table.name === "document_chunk"
1025тЖТ      ? "document_chunk"
1026тЖТ      : row.in.table.name === "git_commit"
1027тЖТ        ? "git_commit"
1028тЖТ        : "message",
1029тЖТ    confidence: row.confidence,
1030тЖТ    extractedAt: toIsoString(row.extracted_at),
1031тЖТ    ...(row.in.table.name === "message" && convMap?.get(row.in.id as string)
1032тЖТ      ? { conversationId: convMap.get(row.in.id as string) }
1033тЖТ      : {}),
1034тЖТ    ...(row.evidence ? { evidence: row.evidence } : {}),
1035тЖТ    ...(row.evidence_source ? { evidenceSource: toRecordIdString(row.evidence_source) } : {}),
1036тЖТ    ...(row.resolved_from ? { resolvedFrom: toRecordIdString(row.resolved_from) } : {}),
1037тЖТ    ...(row.from_text ? { fromText: row.from_text } : {}),
1038тЖТ  } satisfies EntityProvenance));
1039тЖТ
1040тЖТ  return {
1041тЖТ    entity: {
1042тЖТ      id: toRecordIdString(input.entityRecord),
1043тЖТ      kind: table,
1044тЖТ      name,
1045тЖТ      data: row,
1046тЖТ    },
1047тЖТ    relationships,
1048тЖТ    provenance,
1049тЖТ  };

